window.PL_MATERIAIS = [

  {
    id: 'm-conjuntos-numericos',
    titulo: 'Conjuntos Numéricos: N, Z, Q e R',
    aulaIds: ['mat-01', 'mb-01'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-01-conjuntos-numericos.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Os números se organizam em conjuntos encaixados: <b>N ⊂ Z ⊂ Q ⊂ R</b>.</p><ul><li><b>Naturais (N)</b> = {0, 1, 2, 3, …} — contagem. O <b>zero é natural</b>.</li><li><b>Inteiros (Z)</b> = {…, −2, −1, 0, 1, 2, …} — entram os negativos.</li><li><b>Racionais (Q)</b> — todo número que pode ser escrito como fração a/b (b ≠ 0): inteiros, decimais exatos e <b>dízimas periódicas</b>.</li><li><b>Irracionais (I)</b> — dízimas NÃO periódicas: √2, π, 0,101001000…</li><li><b>Reais (R)</b> = racionais ∪ irracionais.</li></ul>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li><b>Fração geratriz</b> — período sobre tantos 9 quantos forem os algarismos do período: 0,444… = 4/9; 0,232323… = 23/99; 2,777… = 2 + 7/9 = 25/9.</li><li><b>Oposto</b> de a é −a; <b>inverso</b> de a é 1/a (a ≠ 0).</li><li>Entre dois racionais distintos <b>sempre existe outro racional</b> (e também um irracional).</li><li>racional + irracional = <b>irracional</b>; racional × irracional (≠0) = <b>irracional</b>.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>(estilo UNEB) Entre os números −15; 0,333…; √16; √7 e 12/4, quantos são inteiros e quantos são irracionais?</p><div class='sol'><b>Resolução.</b> √16 = 4 (inteiro) e 12/4 = 3 (inteiro); com −15, são <b>3 inteiros</b>. 0,333… = 1/3 é racional. Só √7 é dízima não periódica → <b>1 irracional</b>. A banca adora esconder inteiros dentro de raízes exatas e frações aparentes.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Caiu “classifique o número”? Siga a receita:</p><ol class='passos'><li>É fração, decimal exato ou dízima COM período? → <b>racional</b>.</li><li>Tem raiz? Calcule: raiz exata (√16 = 4) vira <b>inteiro</b>; raiz não exata (√7) é <b>irracional</b>.</li><li>É π ou dízima SEM período? → <b>irracional</b>.</li><li>Aparece “i”? → <b>complexo não real</b> (não entra em R).</li><li>Lembre os encaixes: todo natural é inteiro, todo inteiro é racional, todo racional é real.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Encontre a fração geratriz de 1,2444… (dízima composta: o 2 não repete, o 4 repete).</p><div class='sol'><b>Passo 1:</b> parte que não repete depois da vírgula: “2” (1 algarismo); período: “4” (1 algarismo).<br><b>Passo 2:</b> numerador = tudo até o fim do 1º período SEM a vírgula, menos a parte que não repete: 124 − 12 = 112.<br><b>Passo 3:</b> denominador = um 9 por algarismo do período e um 0 por algarismo do ante-período: 90.<br><b>Resposta:</b> 112/90 = <b>56/45</b>. Confira na calculadora: 56 ÷ 45 = 1,2444… ✓</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>“Todo real é racional” — <b>FALSO</b> (π e √2 são reais e não são racionais).</li><li>0,999… = 1 (dízima de período 9 é o próprio inteiro).</li><li>√2 + (−√2) = 0: a soma de DOIS irracionais <b>pode</b> ser racional.</li><li>Zero é natural, é par e é múltiplo de todo número — mas <b>não é divisor</b> de nenhum.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 240' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='8' y='8' width='504' height='224' rx='16' fill='none' stroke='#6B89FF' stroke-width='2'/>\n<text x='26' y='34' fill='#dbe3f8' font-size='16' font-weight='bold'>R — Reais</text>\n<rect x='26' y='48' width='300' height='168' rx='14' fill='rgba(107,137,255,.08)' stroke='#6B89FF' stroke-width='1.5'/>\n<text x='40' y='72' fill='#dbe3f8' font-size='14' font-weight='bold'>Q — Racionais</text>\n<rect x='40' y='84' width='200' height='116' rx='12' fill='rgba(107,137,255,.10)' stroke='#6B89FF' stroke-width='1.5'/>\n<text x='54' y='106' fill='#dbe3f8' font-size='13' font-weight='bold'>Z — Inteiros</text>\n<rect x='54' y='116' width='120' height='68' rx='10' fill='rgba(107,137,255,.14)' stroke='#6B89FF' stroke-width='1.5'/>\n<text x='66' y='139' fill='#dbe3f8' font-size='12' font-weight='bold'>N — Naturais</text>\n<text x='66' y='162' fill='#8fa3d8' font-size='11'>0, 1, 2, 3…</text>\n<text x='185' y='160' fill='#8fa3d8' font-size='11'>−1, −7…</text>\n<text x='252' y='150' fill='#8fa3d8' font-size='11'>1/2, 0,75,</text>\n<text x='252' y='166' fill='#8fa3d8' font-size='11'>dízimas</text>\n<rect x='346' y='48' width='150' height='168' rx='14' fill='rgba(251,191,36,.08)' stroke='#fbbf24' stroke-width='1.5'/>\n<text x='362' y='74' fill='#fbbf24' font-size='13' font-weight='bold'>I — Irracionais</text>\n<text x='362' y='100' fill='#8fa3d8' font-size='12'>√2 ≈ 1,4142…</text>\n<text x='362' y='122' fill='#8fa3d8' font-size='12'>π ≈ 3,1415…</text>\n<text x='362' y='150' fill='#8fa3d8' font-size='10.5'>dízimas que NÃO</text>\n<text x='362' y='165' fill='#8fa3d8' font-size='10.5'>têm período</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>0,737373… é racional ou irracional? Se for racional, escreva a fração geratriz.</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>É <b>racional</b> — toda dízima periódica é. Período de 2 algarismos (73) → geratriz = <b>73/99</b>. Verifique: 73 ÷ 99 = 0,7373…</div></details>" }
    ]
  },

  {
    id: 'm-irracionais-complexos',
    titulo: 'Números Irracionais, Reais e Complexos',
    aulaIds: ['mat-02'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-05-irracionais-complexos.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Raiz quadrada de número negativo não existe em R — por isso criou-se a <b>unidade imaginária</b>: <b>i² = −1</b>. Todo número complexo tem a forma algébrica <b>z = a + bi</b> (a = parte real, b = parte imaginária).</p><ul><li>b = 0 → z é real; a = 0 e b ≠ 0 → z é <b>imaginário puro</b>.</li><li><b>Conjugado</b>: z̄ = a − bi (troca o sinal da parte imaginária).</li><li><b>Módulo</b>: |z| = √(a² + b²) — distância até a origem no plano complexo.</li></ul>" },
      { ic: '🧮', t: 'Operações e potências de i', h: "<ul><li>Soma/subtração: opera-se parte real com real, imaginária com imaginária.</li><li>Multiplicação: distributiva normal, trocando i² por −1.</li><li>Divisão: multiplica em cima e embaixo pelo <b>conjugado do denominador</b>.</li><li>Potências de i são cíclicas de 4 em 4: i¹ = i, i² = −1, i³ = −i, i⁴ = 1. Para iⁿ, use o <b>resto da divisão de n por 4</b>: i²⁰²⁶ → 2026 ÷ 4 deixa resto 2 → i²⁰²⁶ = −1.</li><li>Forma trigonométrica: z = |z|·(cos θ + i·sen θ), onde tg θ = b/a.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>Calcule (2 + 3i) · (1 − i).</p><div class='sol'><b>Resolução.</b> Distributiva: 2·1 + 2·(−i) + 3i·1 + 3i·(−i) = 2 − 2i + 3i − 3i². Como i² = −1: −3i² = +3. Resultado: (2 + 3) + (−2 + 3)i = <b>5 + i</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Operações com complexos na prova — o caminho seguro:</p><ol class='passos'><li>Soma/subtração: junte parte real com real e imaginária com imaginária.</li><li>Multiplicação: distributiva normal e troque <b>i² por −1</b> no final.</li><li>Divisão: multiplique em cima e embaixo pelo <b>conjugado do denominador</b>.</li><li>Potência de i: divida o expoente por 4 e use só o <b>resto</b> (i¹=i, i²=−1, i³=−i, i⁰=1).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Calcule (3 + i) ÷ (1 − 2i).</p><div class='sol'><b>Passo 1:</b> conjugado do denominador: (1 + 2i).<br><b>Passo 2:</b> multiplique em cima e embaixo: [(3+i)(1+2i)] / [(1−2i)(1+2i)].<br><b>Passo 3:</b> numerador: 3 + 6i + i + 2i² = 3 + 7i − 2 = 1 + 7i. Denominador: 1² + 2² = 5.<br><b>Resposta:</b> (1 + 7i)/5 = <b>1/5 + 7i/5</b>.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>“2 + 3i é irracional” — FALSO: é <b>complexo não real</b>; irracional é categoria de número REAL.</li><li>Igualdade de complexos: a + bi = c + di exige a = c <b>e</b> b = d (duas equações).</li><li>|z| nunca é negativo; |3 − 4i| = √(9+16) = 5.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='8' y='8' width='504' height='204' rx='16' fill='none' stroke='#fb923c' stroke-width='2'/>\n<text x='26' y='34' fill='#fb923c' font-size='15' font-weight='bold'>C — Complexos (a + bi)</text>\n<rect x='26' y='50' width='290' height='146' rx='13' fill='rgba(107,137,255,.08)' stroke='#6B89FF' stroke-width='1.5'/>\n<text x='42' y='76' fill='#dbe3f8' font-size='13' font-weight='bold'>R — Reais (b = 0)</text>\n<text x='42' y='100' fill='#8fa3d8' font-size='11.5'>−3 · 0,5 · √2 · π</text>\n<rect x='344' y='50' width='152' height='146' rx='13' fill='rgba(52,211,153,.08)' stroke='#34d399' stroke-width='1.5'/>\n<text x='358' y='76' fill='#34d399' font-size='12.5' font-weight='bold'>Imaginários</text>\n<text x='358' y='98' fill='#8fa3d8' font-size='11.5'>2 + 3i · −i</text>\n<text x='358' y='120' fill='#8fa3d8' font-size='11.5'>i² = −1</text>\n<text x='42' y='150' fill='#dbe3f8' font-size='12' font-weight='bold'>Ciclo de i:</text>\n<text x='42' y='172' fill='#8fa3d8' font-size='12'>i¹=i · i²=−1 · i³=−i · i⁴=1 (repete de 4 em 4)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Calcule i⁴⁵.</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>As potências de i repetem de 4 em 4. 45 ÷ 4 = 11, resto <b>1</b> → i⁴⁵ = i¹ = <b>i</b>.</div></details>" }
    ]
  },

  {
    id: 'm-pa',
    titulo: 'Progressão Aritmética (PA)',
    aulaIds: ['mat-03'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-06-pa.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>PA é a sequência em que cada termo é o anterior <b>somado</b> de uma constante r (razão). r &gt; 0: crescente; r &lt; 0: decrescente; r = 0: constante.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Termo geral</b>: aₙ = a₁ + (n − 1)·r</li><li><b>Soma dos n primeiros</b>: Sₙ = (a₁ + aₙ)·n / 2</li><li><b>Termo médio</b>: numa PA de 3 termos, o do meio é a média dos vizinhos: b = (a + c)/2.</li><li>Quantidade de termos entre dois valores: n = (último − primeiro)/r + 1.</li><li>Múltiplos de k entre A e B: ache o primeiro e o último múltiplo no intervalo e aplique a fórmula acima.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real adaptada', h: "<p class='en'>(CONSULTEC) Um remédio é tomado assim: 24 comprimidos por dia na 1ª semana, 22 na 2ª, 20 na 3ª…, reduzindo 2 por semana até parar. Se cada caixa tem 80 comprimidos, qual o número mínimo de caixas para o tratamento?</p><div class='sol'><b>Resolução.</b> Comprimidos por semana: 7·(24 + 22 + … + 2). A PA 24, 22, …, 2 tem n = (24−2)/2 + 1 = 12 termos e soma S = (24+2)·12/2 = 156. Total: 7 · 156 = 1.092 comprimidos. Caixas: 1092 ÷ 80 = 13,65 → <b>14 caixas</b> (sempre arredonde PARA CIMA quando a pergunta é “quantas caixas”).</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Problema de PA? Receita em 4 passos:</p><ol class='passos'><li>Identifique <b>a₁</b> (primeiro valor) e <b>r</b> (quanto soma de um termo para o outro).</li><li>A pergunta é sobre UM termo? Use aₙ = a₁ + (n−1)·r.</li><li>A pergunta é sobre o TOTAL acumulado? Use Sₙ = (a₁ + aₙ)·n/2 (ache aₙ antes).</li><li>Confira se o enunciado pede o termo ou a soma — é a pegadinha nº 1.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>A soma 1 + 2 + 3 + … + 100 (história clássica de Gauss criança).</p><div class='sol'><b>Passo 1:</b> é uma PA com a₁ = 1, r = 1 e n = 100 termos; o último é a₁₀₀ = 100.<br><b>Passo 2:</b> truque de Gauss: o primeiro + o último = 1 + 100 = 101; o segundo + o penúltimo = 2 + 99 = 101… são 50 pares de 101.<br><b>Resposta:</b> S = 101 × 50 = <b>5.050</b> — exatamente a fórmula Sₙ = (a₁+aₙ)·n/2.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>A banca pergunta a <b>soma</b> e oferece o último termo como distrator (e vice-versa). Leia o que se pede!</li><li>“Quantos múltiplos de 7 entre 100 e 300?” → primeiro: 105, último: 294 → (294−105)/7 + 1 = 28.</li><li>Em problemas de “dia/semana”, confira se o 1º dia conta como termo 1.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 150' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='20' y1='110' x2='500' y2='110' stroke='#6B89FF' stroke-width='2'/>\n<circle cx='70' cy='110' r='5' fill='#6B89FF'/><text x='70' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>5</text><circle cx='170' cy='110' r='5' fill='#6B89FF'/><text x='170' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>8</text><circle cx='270' cy='110' r='5' fill='#6B89FF'/><text x='270' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>11</text><circle cx='370' cy='110' r='5' fill='#6B89FF'/><text x='370' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>14</text><circle cx='470' cy='110' r='5' fill='#6B89FF'/><text x='470' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>17</text>\n<path d='M 78 92 Q 120 60 162 92' fill='none' stroke='#fbbf24' stroke-width='1.6'/><text x='120' y='56' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>+3</text><path d='M 178 92 Q 220 60 262 92' fill='none' stroke='#fbbf24' stroke-width='1.6'/><text x='220' y='56' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>+3</text><path d='M 278 92 Q 320 60 362 92' fill='none' stroke='#fbbf24' stroke-width='1.6'/><text x='320' y='56' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>+3</text><path d='M 378 92 Q 420 60 462 92' fill='none' stroke='#fbbf24' stroke-width='1.6'/><text x='420' y='56' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>+3</text>\n<text x='260' y='26' fill='#8fa3d8' font-size='12' text-anchor='middle'>PA: sempre SOMA a mesma razão r</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Numa PA com a₁ = 7 e r = 4, qual é o 20º termo?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>aₙ = a₁ + (n−1)·r → a₂₀ = 7 + 19·4 = 7 + 76 = <b>83</b>.</div></details>" }
    ]
  },

  {
    id: 'm-pg',
    titulo: 'Progressão Geométrica (PG) — com revisão de PA',
    aulaIds: ['mat-04', 'mb-06'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-07-pg.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>PG é a sequência em que cada termo é o anterior <b>multiplicado</b> por uma constante q (razão). Crescimentos percentuais repetidos (juros, “dobra a cada hora”) são PGs disfarçadas: aumentar 25% ao mês = PG de razão 1,25.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave (PG e PA juntas)', h: "<ul><li><b>PG — termo geral</b>: aₙ = a₁ · qⁿ⁻¹</li><li><b>PG — soma finita</b>: Sₙ = a₁·(qⁿ − 1)/(q − 1)</li><li><b>PG — soma infinita</b> (|q| &lt; 1): S∞ = a₁/(1 − q)</li><li><b>PG — termo médio</b>: b² = a·c (média geométrica).</li><li><b>PA — recap</b>: aₙ = a₁ + (n−1)r e Sₙ = (a₁+aₙ)n/2. Na PA soma-se; na PG multiplica-se.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(IBFC · Soldado PM BA) O nono termo da sequência 3, −6, 12, −24, … representa o total de candidatos presentes. Se 210 foram aprovados, quantos foram reprovados?</p><div class='sol'><b>Resolução.</b> PG de razão q = −2. a₉ = 3·(−2)⁸ = 3·256 = 768 presentes. Reprovados: 768 − 210 = <b>558</b>. Atenção ao sinal: (−2)⁸ é positivo porque o expoente é par.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Problema de PG (crescimento que multiplica)? Receita:</p><ol class='passos'><li>Identifique <b>a₁</b> e a razão <b>q</b> (“dobra” → q=2; “+25%” → q=1,25; “cai pela metade” → q=0,5).</li><li>Conte DIREITO o nº de multiplicações: das 10h às 14h são 4, não 5.</li><li>Um termo: aₙ = a₁·qⁿ⁻¹. Total: Sₙ = a₁(qⁿ−1)/(q−1).</li><li>Soma infinita (só se |q| < 1): S∞ = a₁/(1−q).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Uma bola é solta e a cada quique sobe metade da altura. Se subiu 6 m no 1º quique, quanto sobe ao todo somando todos os quiques?</p><div class='sol'><b>Passo 1:</b> alturas: 6, 3, 1,5, 0,75… é PG infinita com a₁ = 6 e q = 1/2.<br><b>Passo 2:</b> como |q| < 1, a soma infinita existe: S∞ = a₁/(1−q) = 6/(1−0,5).<br><b>Resposta:</b> 6/0,5 = <b>12 metros</b>.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>“Triplica a cada hora, das 10h às 14h” = <b>4</b> multiplicações (3⁴), não 5.</li><li>Poupança a 0,5% ao mês → montantes formam PG de razão <b>1,005</b> (não 0,005!).</li><li>Soma infinita só existe se |q| &lt; 1: 8 + 4 + 2 + 1 + … = 8/(1 − 1/2) = 16.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 150' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='20' y1='110' x2='500' y2='110' stroke='#6B89FF' stroke-width='2'/>\n<circle cx='70' cy='110' r='5' fill='#6B89FF'/><text x='70' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>2</text><circle cx='170' cy='110' r='5' fill='#6B89FF'/><text x='170' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>6</text><circle cx='270' cy='110' r='5' fill='#6B89FF'/><text x='270' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>18</text><circle cx='370' cy='110' r='5' fill='#6B89FF'/><text x='370' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>54</text><circle cx='470' cy='110' r='5' fill='#6B89FF'/><text x='470' y='140' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>162</text>\n<path d='M 78 92 Q 120 60 162 92' fill='none' stroke='#34d399' stroke-width='1.6'/><text x='120' y='56' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>×3</text><path d='M 178 92 Q 220 60 262 92' fill='none' stroke='#34d399' stroke-width='1.6'/><text x='220' y='56' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>×3</text><path d='M 278 92 Q 320 60 362 92' fill='none' stroke='#34d399' stroke-width='1.6'/><text x='320' y='56' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>×3</text><path d='M 378 92 Q 420 60 462 92' fill='none' stroke='#34d399' stroke-width='1.6'/><text x='420' y='56' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>×3</text>\n<text x='260' y='26' fill='#8fa3d8' font-size='12' text-anchor='middle'>PG: sempre MULTIPLICA pela mesma razão q</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Na PG 5, 10, 20, …, qual é o 8º termo?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>q = 2 → a₈ = 5 · 2⁷ = 5 · 128 = <b>640</b>.</div></details>" }
    ]
  },

  {
    id: 'm-primos-mmc-mdc',
    titulo: 'Números Primos, MMC e MDC',
    aulaIds: ['mat-05', 'mb-02', 'cr-01'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-04-mmc-mdc.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p><b>Primo</b> é o natural com exatamente dois divisores: 1 e ele mesmo (2, 3, 5, 7, 11, 13…). O 2 é o único primo par; <b>1 não é primo</b>. Todo número se decompõe de forma única em fatores primos — e dessa fatoração saem MMC e MDC.</p>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li><b>MDC</b> (máximo divisor comum): fatores comuns com os MENORES expoentes. Uso típico: <b>repartir/cortar em pedaços iguais máximos</b>.</li><li><b>MMC</b> (mínimo múltiplo comum): todos os fatores com os MAIORES expoentes. Uso típico: <b>eventos que se repetem e voltam a coincidir</b>.</li><li><b>MMC × MDC = a × b</b> (para dois números).</li><li><b>Quantidade de divisores</b>: fatore e multiplique os expoentes somados de 1: 72 = 2³·3² → (3+1)·(2+1) = 12 divisores.</li><li>Critérios de divisibilidade: por 3/9 (soma dos algarismos), por 4 (dois últimos), por 6 (par e divisível por 3).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>Três viaturas saem juntas da base e retornam a cada 12, 15 e 20 dias, respectivamente. Depois de quantos dias as três voltarão a se encontrar na base?</p><div class='sol'><b>Resolução.</b> Encontro de ciclos = MMC. 12 = 2²·3; 15 = 3·5; 20 = 2²·5 → MMC = 2²·3·5 = <b>60 dias</b>. Se fosse “cortar três cordas de 12, 15 e 20 m em pedaços iguais máximos”, seria MDC = 1… cuidado para não inverter!</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>MMC ou MDC? Decida pela PERGUNTA do problema:</p><ol class='passos'><li>“Voltarão a coincidir / mesmo dia / juntos de novo” → <b>MMC</b>.</li><li>“Maior pedaço igual / dividir sem sobra / menor nº de grupos” → <b>MDC</b>.</li><li>Fatore os números em primos (2, 3, 5, 7…).</li><li>MDC = fatores COMUNS com menor expoente; MMC = TODOS os fatores com maior expoente.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Duas fitas, de 84 cm e 60 cm, devem ser cortadas em pedaços iguais e do MAIOR tamanho possível. Qual o tamanho de cada pedaço?</p><div class='sol'><b>Passo 1:</b> “maior pedaço igual” → MDC.<br><b>Passo 2:</b> fatore: 84 = 2²·3·7 e 60 = 2²·3·5.<br><b>Passo 3:</b> fatores comuns com menor expoente: 2²·3 = 12.<br><b>Resposta:</b> pedaços de <b>12 cm</b> (7 pedaços de uma fita e 5 da outra, sem sobra).</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>“Juntos novamente” / “mesmo dia” → MMC. “Maior tamanho igual” / “menor número de pedaços” → MDC.</li><li>1 não é primo e 2 é primo — afirmações clássicas de V/F.</li><li>O MDC de dois números consecutivos é sempre 1.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<text x='130' y='30' fill='#dbe3f8' font-size='14' text-anchor='middle' font-weight='bold'>12 = 2 · 2 · 3</text>\n<text x='390' y='30' fill='#dbe3f8' font-size='14' text-anchor='middle' font-weight='bold'>18 = 2 · 3 · 3</text>\n<circle cx='200' cy='130' r='80' fill='rgba(107,137,255,.10)' stroke='#6B89FF' stroke-width='2'/>\n<circle cx='320' cy='130' r='80' fill='rgba(251,191,36,.10)' stroke='#fbbf24' stroke-width='2'/>\n<text x='150' y='125' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>2</text>\n<text x='260' y='118' fill='#34d399' font-size='15' text-anchor='middle' font-weight='bold'>2 · 3</text>\n<text x='370' y='125' fill='#dbe3f8' font-size='15' text-anchor='middle' font-weight='bold'>3</text>\n<text x='260' y='145' fill='#34d399' font-size='11' text-anchor='middle'>comum = MDC = 6</text>\n<text x='260' y='225' fill='#8fa3d8' font-size='12' text-anchor='middle'>MMC = tudo junto = 2·2·3·3 = 36 · Confere: MMC × MDC = 36 × 6 = 216 = 12 × 18 ✓</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Dois ônibus saem juntos do terminal: um a cada 15 min e outro a cada 20 min. Depois de quanto tempo saem juntos de novo?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>“Voltar a coincidir” = MMC. 15 = 3·5, 20 = 2²·5 → MMC = 2²·3·5 = <b>60 minutos</b>.</div></details>" }
    ]
  },

  {
    id: 'm-fracoes',
    titulo: 'Números Racionais e Frações',
    aulaIds: ['mat-06', 'mb-03', 'cr-02'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-02-numeros-racionais.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Fração é divisão: a/b é “a dividido em b partes”. As quatro operações: <b>soma/subtração</b> exigem mesmo denominador (use o MMC); <b>multiplicação</b> é direto (numerador × numerador); <b>divisão</b> é multiplicar pelo inverso da segunda.</p>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li><b>Fração DE um valor</b>: “2/5 de 300” = 2/5 × 300 = 120. “De” = vezes.</li><li><b>Fração de fração</b>: 2/3 de 3/4 = 1/2.</li><li><b>Problema do resto</b>: gastou 2/5 e 1/3 → gastou 6/15 + 5/15 = 11/15 → <b>sobraram 4/15</b>. Se o resto vale R$ 720, então 1/15 = 180 e o todo = R$ 2.700.</li><li><b>Comparação</b>: iguale denominadores ou compare em decimal.</li><li>Decimal exato → fração: 0,25 = 25/100 = 1/4 (simplifique sempre).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(IBFC · Soldado PM BA/2017) Antônio gastou 50% de dois quintos do valor que possuía e ainda sobraram R$ 160,00. O valor gasto foi:</p><div class='sol'><b>Resolução.</b> Gastou metade de 2/5 = <b>1/5</b> do total → sobraram 4/5 = R$ 160 → o todo era R$ 200 → gastou 1/5 de 200 = <b>R$ 40,00</b>. A pergunta é o GASTO, não o total — leia duas vezes.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>As 4 operações com frações — receita relâmpago:</p><ol class='passos'><li>Somar/subtrair: iguale os denominadores pelo MMC e opere só os numeradores.</li><li>Multiplicar: em linha reta (cima×cima, baixo×baixo). Simplifique antes se puder.</li><li>Dividir: mantém a primeira e <b>multiplica pelo inverso</b> da segunda.</li><li>“DE” no problema = vezes: 2/5 de 300 = 2/5 × 300.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Quantos copos de 1/6 de litro cabem em uma jarra com 2/3 de litro?</p><div class='sol'><b>Passo 1:</b> “quantos cabem” = divisão: (2/3) ÷ (1/6).<br><b>Passo 2:</b> mantém a primeira e multiplica pelo inverso: 2/3 × 6/1 = 12/3.<br><b>Resposta:</b> <b>4 copos</b>. Faz sentido: cada litro tem 6 copos, e 2/3 de 6 = 4. ✓</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Misturas e razões: garrafas de MESMO volume com razões 1:2 e 3:2 → some frações do mesmo todo (X = 1/3 + 3/5 = 14/15 do volume de uma garrafa).</li><li>Dividir por fração = multiplicar pelo inverso: (2/3) ÷ (4/9) = 2/3 · 9/4 = 3/2.</li><li>Frações de frações encadeadas: resolva da direita para a esquerda com calma.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 190' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<circle cx='110' cy='95' r='70' fill='rgba(107,137,255,.08)' stroke='#6B89FF' stroke-width='2'/>\n<path d='M110 95 L110 25 A70 70 0 0 1 180 95 Z' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/>\n<path d='M110 95 L180 95 A70 70 0 0 1 110 165 Z' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/>\n<path d='M110 95 L110 165 A70 70 0 0 1 40 95 Z' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/>\n<line x1='110' y1='95' x2='110' y2='25' stroke='#6B89FF'/><line x1='110' y1='95' x2='40' y2='95' stroke='#6B89FF'/>\n<text x='110' y='15' fill='#8fa3d8' font-size='12' text-anchor='middle'>3/4 pintado</text>\n<g>\n<rect x='250' y='55' width='240' height='34' rx='8' fill='none' stroke='#6B89FF' stroke-width='1.5'/>\n<rect x='250' y='55' width='48' height='34' fill='rgba(52,211,153,.35)' stroke='#6B89FF'/><rect x='298' y='55' width='48' height='34' fill='rgba(52,211,153,.35)' stroke='#6B89FF'/><rect x='346' y='55' width='48' height='34' fill='rgba(52,211,153,.35)' stroke='#6B89FF'/>\n<text x='370' y='45' fill='#8fa3d8' font-size='12' text-anchor='middle'>3/5 de 300 = 180</text>\n<text x='274' y='77' fill='#dbe3f8' font-size='12' text-anchor='middle'>60</text><text x='322' y='77' fill='#dbe3f8' font-size='12' text-anchor='middle'>60</text><text x='370' y='77' fill='#dbe3f8' font-size='12' text-anchor='middle'>60</text><text x='418' y='77' fill='#dbe3f8' font-size='12' text-anchor='middle'>60</text><text x='466' y='77' fill='#dbe3f8' font-size='12' text-anchor='middle'>60</text>\n<text x='370' y='115' fill='#8fa3d8' font-size='12' text-anchor='middle'>cada parte = 300 ÷ 5 = 60</text>\n<text x='370' y='135' fill='#8fa3d8' font-size='12' text-anchor='middle'>“DE” = vezes: 3/5 × 300</text>\n</g>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Uma pessoa gastou parte do salário e sobraram 2/5 de R$ 300 que tinha. Quanto ela gastou?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Sobrou 2/5 × 300 = 120 → gastou 300 − 120 = <b>R$ 180</b> (que é 3/5 de 300).</div></details>" }
    ]
  },

  {
    id: 'm-potencia-radiciacao',
    titulo: 'Potenciação e Radiciação',
    aulaIds: ['mat-07', 'mb-04'],
    pdfOriginal: 'assets/aulas/cfo-sd/aula-03-dizimas-potenciacao.pdf',
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Potência é multiplicação repetida; raiz é a operação inversa. Dominar as <b>propriedades</b> resolve 90% das questões — quase nunca se calcula força bruta.</p>" },
      { ic: '🧮', t: 'Propriedades (decore!)', h: "<ul><li>aᵐ · aⁿ = aᵐ⁺ⁿ &nbsp;|&nbsp; aᵐ ÷ aⁿ = aᵐ⁻ⁿ &nbsp;|&nbsp; (aᵐ)ⁿ = aᵐ·ⁿ</li><li>(a·b)ⁿ = aⁿ·bⁿ &nbsp;|&nbsp; a⁰ = 1 (a ≠ 0) &nbsp;|&nbsp; a⁻ⁿ = 1/aⁿ</li><li>Expoente fracionário: a^(m/n) = ⁿ√(aᵐ). Ex.: 8^(2/3) = (³√8)² = 4.</li><li>√(a·b) = √a·√b — mas <b>√(a+b) ≠ √a + √b</b>!</li><li>Racionalização: 1/√2 = √2/2 (multiplica em cima e embaixo por √2).</li><li>Notação científica: 0,00045 = 4,5 × 10⁻⁴.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>Simplifique: (2³ · 2⁵) ÷ 2⁶ + (−2)² − 2².</p><div class='sol'><b>Resolução.</b> 2³·2⁵ = 2⁸; 2⁸ ÷ 2⁶ = 2² = 4. (−2)² = 4 e 2² = 4 → 4 + 4 − 4 = <b>4</b>. Atenção: (−2)² = +4, mas −2² = −4 (o sinal fora do parêntese não entra na potência).</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Expressão cheia de potências? Não calcule número gigante — SIMPLIFIQUE:</p><ol class='passos'><li>Mesma base multiplicando? SOME os expoentes (aᵐ·aⁿ = aᵐ⁺ⁿ).</li><li>Mesma base dividindo? SUBTRAIA os expoentes.</li><li>Potência de potência? MULTIPLIQUE os expoentes.</li><li>Expoente negativo = inverso; expoente fracionário = raiz.</li><li>Só no final transforme em número.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Simplifique (5² · 5⁴) ÷ 5³.</p><div class='sol'><b>Passo 1:</b> multiplicação de mesma base: 5² · 5⁴ = 5⁶.<br><b>Passo 2:</b> divisão de mesma base: 5⁶ ÷ 5³ = 5³.<br><b>Resposta:</b> 5³ = <b>125</b>. Quem multiplica tudo na mão (25 × 625 ÷ 125) gasta o triplo do tempo para chegar no mesmo lugar.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>(−2)² ≠ −2² — a clássica das clássicas.</li><li>2³ · 2⁵ NÃO é 4⁸ (base não muda na multiplicação de mesma base).</li><li>√(x²) = |x| — para x negativo o resultado é positivo.</li><li>0⁰ é indeterminado; 0ⁿ = 0 para n &gt; 0.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 150' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<text x='80' y='80' fill='#dbe3f8' font-size='22' font-weight='bold'>2³</text>\n<path d='M120 62 Q 200 28 280 62' fill='none' stroke='#34d399' stroke-width='2' marker-end='url(#a1)'/>\n<text x='200' y='26' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>potência: 2·2·2</text>\n<text x='300' y='80' fill='#dbe3f8' font-size='22' font-weight='bold'>8</text>\n<path d='M290 96 Q 200 130 130 96' fill='none' stroke='#fbbf24' stroke-width='2' marker-end='url(#a2)'/>\n<text x='205' y='138' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>raiz: ³√8 = 2 (caminho de volta)</text>\n<text x='420' y='62' fill='#8fa3d8' font-size='12'>a⁰ = 1</text>\n<text x='420' y='84' fill='#8fa3d8' font-size='12'>a⁻ⁿ = 1/aⁿ</text>\n<defs><marker id='a1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><path d='M0,0 L6,3 L0,6 Z' fill='#34d399'/></marker>\n<marker id='a2' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><path d='M0,0 L6,3 L0,6 Z' fill='#fbbf24'/></marker></defs>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Calcule (−3)² + (−2)³.</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>(−3)² = +9 (expoente par) e (−2)³ = −8 (expoente ímpar) → 9 − 8 = <b>1</b>.</div></details>" }
    ]
  },

  {
    id: 'm-teoria-conjuntos-1',
    titulo: 'Teoria dos Conjuntos — Operações',
    aulaIds: ['mat-08', 'mb-07'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Conjunto é coleção de elementos. <b>∈</b> relaciona elemento↔conjunto; <b>⊂</b> relaciona conjunto↔conjunto. O vazio (∅) é subconjunto de todo conjunto.</p>" },
      { ic: '🧮', t: 'Operações e fórmulas', h: "<ul><li><b>União</b> A ∪ B: tudo que está em A <b>ou</b> em B.</li><li><b>Interseção</b> A ∩ B: o que está em A <b>e</b> em B ao mesmo tempo.</li><li><b>Diferença</b> A − B: está em A e NÃO está em B.</li><li><b>Complementar</b>: o que falta para completar o universo.</li><li>Se A ⊂ B: A ∩ B = A e A ∪ B = B.</li><li><b>Conjunto das partes</b>: A com n elementos tem <b>2ⁿ subconjuntos</b>. {a, b, c} → 2³ = 8.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>Dados A = {1, 2, 3} e B = {2, 3, 4}: determine A ∪ B, A ∩ B, A − B e o número de subconjuntos de A ∪ B.</p><div class='sol'><b>Resolução.</b> A ∪ B = {1, 2, 3, 4}; A ∩ B = {2, 3}; A − B = {1} (só o que é exclusivo de A). A ∪ B tem 4 elementos → 2⁴ = <b>16 subconjuntos</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Operações entre conjuntos — tradução direta:</p><ol class='passos'><li>∪ (união) = “OU”: junta tudo, sem repetir elemento.</li><li>∩ (interseção) = “E”: só o que está nos DOIS.</li><li>A − B = o que é de A e NÃO é de B (a ordem importa!).</li><li>Nº de subconjuntos = 2ⁿ (n = quantidade de elementos).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Com A = {1, 2, 3, 4, 5} e B = {4, 5, 6}: calcule A − B, B − A e n(P(B)).</p><div class='sol'><b>A − B:</b> tira de A o que também está em B → {1, 2, 3}.<br><b>B − A:</b> tira de B o que também está em A → {6}. Viu como a ordem muda tudo?<br><b>n(P(B)):</b> B tem 3 elementos → 2³ = <b>8 subconjuntos</b>.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>∅ ⊂ A é sempre verdade; ∅ ∈ A só se o vazio for ELEMENTO listado de A.</li><li>A − B ≠ B − A (a ordem importa).</li><li>n(P(A)) = 2ⁿ conta TODOS os subconjuntos, incluindo ∅ e o próprio A.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 210' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<circle cx='200' cy='105' r='75' fill='rgba(107,137,255,.16)' stroke='#6B89FF' stroke-width='2'/>\n<circle cx='320' cy='105' r='75' fill='rgba(251,191,36,.14)' stroke='#fbbf24' stroke-width='2'/>\n<text x='150' y='60' fill='#dbe3f8' font-size='15' font-weight='bold'>A</text>\n<text x='362' y='60' fill='#fbbf24' font-size='15' font-weight='bold'>B</text>\n<text x='150' y='110' fill='#dbe3f8' font-size='12' text-anchor='middle'>só A</text>\n<text x='260' y='105' fill='#34d399' font-size='12' text-anchor='middle' font-weight='bold'>A ∩ B</text>\n<text x='260' y='122' fill='#8fa3d8' font-size='10'>(os dois)</text>\n<text x='372' y='110' fill='#8fa3d8' font-size='12' text-anchor='middle'>só B</text>\n<text x='260' y='196' fill='#8fa3d8' font-size='12' text-anchor='middle'>A ∪ B = tudo pintado · A − B = “só A” · ∩ = interseção (E) · ∪ = união (OU)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Quantos subconjuntos tem o conjunto {1, 2, 3, 4}?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>2ⁿ = 2⁴ = <b>16 subconjuntos</b> (incluindo o vazio e o próprio conjunto).</div></details>" }
    ]
  },

  {
    id: 'm-teoria-conjuntos-2',
    titulo: 'Teoria dos Conjuntos — Problemas com n(A ∪ B)',
    aulaIds: ['mat-09'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Os problemas de contagem com dois ou três grupos se resolvem com a fórmula da união ou com o <b>diagrama de Venn</b> — sempre preenchendo <b>da interseção para fora</b>.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Dois conjuntos</b>: n(A ∪ B) = n(A) + n(B) − n(A ∩ B)</li><li><b>“Nenhum”</b>: total − n(A ∪ B).</li><li><b>“Apenas A”</b>: n(A) − n(A ∩ B) — “gosta de A” inclui a interseção; “gosta APENAS de A” exclui!</li><li><b>Três conjuntos</b>: preencha o miolo (A∩B∩C) primeiro e vá descontando.</li><li><b>Mínimo de interseção</b> (pior caso): com taxas percentuais, interseção mínima de k grupos = 100% − k·(100% − taxa).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) De 120 pessoas, 42 foram vacinadas contra meningite, 66 contra a gripe e 42 não tomaram nenhuma. Qual a porcentagem que tomou as duas vacinas?</p><div class='sol'><b>Resolução.</b> Pelo menos uma: 120 − 42 = 78. Fórmula da união: 42 + 66 − x = 78 → x = 30. Percentual: 30/120 = <b>25%</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Problema de pesquisa com 2 grupos? Receita do diagrama:</p><ol class='passos'><li>Desenhe os dois círculos e escreva PRIMEIRO a interseção (os que estão nos dois).</li><li>Preencha “só A” = total de A − interseção; “só B” = total de B − interseção.</li><li>Some tudo e compare com o total: a diferença é o “nenhum dos dois”.</li><li>Cuidado com “APENAS A” (exclui a interseção) vs “A” (inclui).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Numa turma de 80 alunos, 45 gostam de Matemática, 38 de Português e 12 não gostam de nenhuma. Quantos gostam das duas? E APENAS de Matemática?</p><div class='sol'><b>Passo 1:</b> pelo menos uma: 80 − 12 = 68.<br><b>Passo 2:</b> união: 45 + 38 − x = 68 → x = <b>15 gostam das duas</b>.<br><b>Passo 3:</b> apenas Matemática: 45 − 15 = <b>30</b>. (Quem responde 45 caiu na pegadinha do “apenas”.)</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>“Gosta de A” vs “gosta APENAS de A” — a diferença é a interseção (e é onde mora o erro).</li><li>Não esqueça o grupo “nenhum dos dois” no total.</li><li>Pior caso com 3 módulos de 70% cada: 100 − 3·30 = <b>10%</b> no mínimo nos três.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='10' y='10' width='500' height='185' rx='14' fill='none' stroke='#52608f' stroke-width='1.5'/>\n<text x='28' y='34' fill='#8fa3d8' font-size='12'>120 pessoas</text>\n<circle cx='200' cy='110' r='70' fill='rgba(107,137,255,.16)' stroke='#6B89FF' stroke-width='2'/>\n<circle cx='310' cy='110' r='70' fill='rgba(251,191,36,.14)' stroke='#fbbf24' stroke-width='2'/>\n<text x='150' y='70' fill='#dbe3f8' font-size='13' font-weight='bold'>Meningite (42)</text>\n<text x='330' y='70' fill='#fbbf24' font-size='13' font-weight='bold'>Gripe (66)</text>\n<text x='160' y='115' fill='#dbe3f8' font-size='17' text-anchor='middle' font-weight='bold'>12</text>\n<text x='255' y='115' fill='#34d399' font-size='17' text-anchor='middle' font-weight='bold'>30</text>\n<text x='350' y='115' fill='#dbe3f8' font-size='17' text-anchor='middle' font-weight='bold'>36</text>\n<text x='448' y='170' fill='#8fa3d8' font-size='13' text-anchor='middle'>nenhuma: 42</text>\n<text x='260' y='220' fill='#8fa3d8' font-size='12' text-anchor='middle'>Preencha SEMPRE do meio (interseção) para fora: 42−30=12 · 66−30=36 · 12+30+36+42=120 ✓</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Em 50 pessoas, 30 gostam de A, 25 de B e 10 dos dois. Quantas não gostam de nenhum?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>União: 30 + 25 − 10 = 45 → nenhum: 50 − 45 = <b>5 pessoas</b>.</div></details>" }
    ]
  },

  {
    id: 'm-algebra',
    titulo: 'Álgebra: Expressões, Produtos Notáveis e Polinômios',
    aulaIds: ['mat-10'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Álgebra é aritmética com letras. As bancas cobram <b>produtos notáveis</b>, <b>fatoração</b> e o valor numérico de <b>polinômios</b> — quase sempre com uma simplificação esperta antes da conta.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li>(a + b)² = a² + 2ab + b² &nbsp;|&nbsp; (a − b)² = a² − 2ab + b²</li><li>(a + b)(a − b) = a² − b² — o “produto da soma pela diferença”.</li><li>Fator comum: ax + ay = a(x + y). Agrupamento: ax + ay + bx + by = (a+b)(x+y).</li><li><b>Valor numérico</b>: P(2) de P(x) = x³ − 2x² + x → 8 − 8 + 2 = 2.</li><li><b>Teorema do resto</b>: o resto de P(x) ÷ (x − a) é P(a). Se P(a) = 0, a é raiz e (x − a) é fator.</li><li>Soma dos coeficientes de P(x) = P(1).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC) A função f(t) = t³ − 14t² + 53t − 40 dá o lucro (em milhares) ao longo de t anos, 1 ≤ t ≤ 10. Excluindo os anos de lucro zero, em quantos anos NÃO houve prejuízo?</p><div class='sol'><b>Resolução.</b> t = 1 zera (1 − 14 + 53 − 40 = 0). Dividindo por (t − 1): t² − 13t + 40 = 0 → t = 5 e t = 8. O sinal do polinômio alterna: positivo em (1, 5), negativo em (5, 8), positivo após 8. Anos inteiros sem prejuízo (excluindo zeros): {2, 3, 4} e {9, 10} → <b>5 anos</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Viu polinômio na prova? Três ataques resolvem quase tudo:</p><ol class='passos'><li>Pedem P(nº)? Só substitua o x e faça a conta com calma (sinais!).</li><li>Pedem raiz/fator? Teste valores pequenos (1, −1, 2…): se P(a) = 0, (x − a) é fator.</li><li>Pedem simplificação? Procure produto notável: a²−b² = (a+b)(a−b) é o mais cobrado.</li><li>Soma dos coeficientes = P(1); termo independente = P(0).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Simplifique (x² − 9) ÷ (x − 3), para x ≠ 3.</p><div class='sol'><b>Passo 1:</b> reconheça o produto notável: x² − 9 = x² − 3² = (x + 3)(x − 3).<br><b>Passo 2:</b> corte o fator comum (x − 3) com o denominador.<br><b>Resposta:</b> <b>x + 3</b>. Teste com x = 4: (16−9)/(4−3) = 7 e 4 + 3 = 7 ✓</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>(a + b)² ≠ a² + b² — o “quadrado da soma” tem o termo 2ab.</li><li>x² + 16 = 0 não tem raiz REAL — não conta na soma de raízes reais.</li><li>x(x−1)(x+3)(x²+16) = 0: raízes reais são 0, 1 e −3 → soma = −2.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='150' y='20' width='120' height='120' fill='rgba(107,137,255,.18)' stroke='#6B89FF' stroke-width='1.5'/>\n<rect x='270' y='20' width='60' height='120' fill='rgba(251,191,36,.15)' stroke='#fbbf24' stroke-width='1.5'/>\n<rect x='150' y='140' width='120' height='60' fill='rgba(251,191,36,.15)' stroke='#fbbf24' stroke-width='1.5'/>\n<rect x='270' y='140' width='60' height='60' fill='rgba(52,211,153,.18)' stroke='#34d399' stroke-width='1.5'/>\n<text x='210' y='86' fill='#dbe3f8' font-size='16' text-anchor='middle' font-weight='bold'>a²</text>\n<text x='300' y='86' fill='#fbbf24' font-size='14' text-anchor='middle' font-weight='bold'>ab</text>\n<text x='210' y='176' fill='#fbbf24' font-size='14' text-anchor='middle' font-weight='bold'>ab</text>\n<text x='300' y='176' fill='#34d399' font-size='14' text-anchor='middle' font-weight='bold'>b²</text>\n<text x='210' y='14' fill='#8fa3d8' font-size='12' text-anchor='middle'>a</text>\n<text x='300' y='14' fill='#8fa3d8' font-size='12' text-anchor='middle'>b</text>\n<text x='400' y='95' fill='#dbe3f8' font-size='14' font-weight='bold'>(a+b)² =</text>\n<text x='400' y='118' fill='#dbe3f8' font-size='14'>a² + 2ab + b²</text>\n<text x='260' y='222' fill='#8fa3d8' font-size='12' text-anchor='middle'>O quadrado da soma É um quadrado de verdade — e o 2ab aparece no desenho!</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Calcule (x + 5)(x − 5).</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Produto da soma pela diferença: a² − b² → <b>x² − 25</b>. Sem distributiva longa!</div></details>" }
    ]
  },

  {
    id: 'm-funcao-1grau',
    titulo: 'Funções do 1° Grau',
    aulaIds: ['mat-11'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>f(x) = ax + b é a reta: <b>a</b> é a inclinação (taxa de variação) e <b>b</b> é o valor inicial (onde corta o eixo y). a &gt; 0: crescente; a &lt; 0: decrescente. Modela tudo que tem <b>valor fixo + valor por unidade</b>: bandeirada + km, assinatura + consumo, custo fixo + custo por peça.</p>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li><b>Raiz</b> (zero): ax + b = 0 → x = −b/a. É onde a reta corta o eixo x.</li><li><b>Encontrar a função por 2 pontos</b>: a = Δy/Δx; depois substitua um ponto para achar b. Pontos (0, 2) e (1, 5): a = 3, b = 2 → f(x) = 3x + 2.</li><li><b>Inequação</b>: resolve como equação; só <b>inverte a desigualdade ao multiplicar/dividir por negativo</b>.</li><li>Crescimento linear no tempo: valor(t) = inicial + taxa·t.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>O custo de produção é C(x) = 250 + 12x. Com orçamento de R$ 1.000, qual o número MÁXIMO de unidades?</p><div class='sol'><b>Resolução.</b> 250 + 12x ≤ 1000 → 12x ≤ 750 → x ≤ 62,5. Como x é inteiro, <b>62 unidades</b> (63 estoura o orçamento — o arredondamento aqui é para BAIXO).</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Problema com “valor fixo + valor por unidade”? É função do 1º grau:</p><ol class='passos'><li>Monte f(x) = (valor por unidade)·x + (valor fixo).</li><li>Deram o total e pedem x? Iguale e resolva a equação.</li><li>Pedem o máximo dentro de um orçamento? Resolva a inequação e arredonde para BAIXO.</li><li>Para achar a função por 2 pontos: a = Δy/Δx, depois substitua um ponto para achar b.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Um táxi cobra R$ 5,00 de bandeirada + R$ 2,50 por km. Uma corrida custou R$ 30,00. Quantos km foram rodados?</p><div class='sol'><b>Passo 1:</b> monte a função: C(x) = 5 + 2,5x.<br><b>Passo 2:</b> iguale ao total: 5 + 2,5x = 30 → 2,5x = 25.<br><b>Resposta:</b> x = <b>10 km</b>. A “bandeirada” é o b (fixo); o “por km” é o a (taxa).</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Máximo de unidades com orçamento → arredonda para baixo; mínimo de caixas para conter algo → para cima.</li><li>Multiplicou a inequação por número negativo? INVERTA o sinal da desigualdade.</li><li>“Variação linear” entre dois anos: ache a taxa anual ANTES de projetar.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='40' y1='180' x2='480' y2='180' stroke='#52608f' stroke-width='1.5'/>\n<line x1='80' y1='210' x2='80' y2='20' stroke='#52608f' stroke-width='1.5'/>\n<line x1='50' y1='196' x2='430' y2='44' stroke='#6B89FF' stroke-width='2.5'/>\n<circle cx='80' cy='184' r='5' fill='#fbbf24'/>\n<text x='98' y='200' fill='#fbbf24' font-size='12'>b (valor inicial)</text>\n<circle cx='90' cy='180' r='5' fill='#34d399'/>\n<text x='118' y='168' fill='#34d399' font-size='12'>raiz: f(x) = 0</text>\n<text x='330' y='60' fill='#dbe3f8' font-size='13' font-weight='bold'>f(x) = ax + b</text>\n<text x='330' y='80' fill='#8fa3d8' font-size='11.5'>a &gt; 0 → sobe (crescente)</text>\n<text x='330' y='98' fill='#8fa3d8' font-size='11.5'>a &lt; 0 → desce (decrescente)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Qual é a raiz de f(x) = 3x − 12?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>3x − 12 = 0 → x = <b>4</b>. É onde a reta corta o eixo x.</div></details>" }
    ]
  },

  {
    id: 'm-funcao-2grau',
    titulo: 'Funções do 2° Grau',
    aulaIds: ['mat-12'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>f(x) = ax² + bx + c é a parábola. a &gt; 0: boca para cima (tem ponto de <b>mínimo</b>); a &lt; 0: boca para baixo (tem <b>máximo</b>). Problemas de “altura máxima”, “lucro máximo” e “área máxima” são sempre o <b>vértice</b>.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Bhaskara</b>: x = (−b ± √Δ)/(2a), com Δ = b² − 4ac.</li><li>Δ &gt; 0: duas raízes; Δ = 0: uma raiz dupla; Δ &lt; 0: nenhuma raiz real.</li><li><b>Soma e produto</b>: S = −b/a e P = c/a (x² − Sx + P = 0). Para raízes 2 e 3: x² − 5x + 6.</li><li><b>Vértice</b>: xᵥ = −b/(2a) e yᵥ = −Δ/(4a).</li><li>Inequação do 2º grau: estude o <b>sinal</b> pela concavidade e raízes.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>A altura de um projétil é h(t) = −5t² + 40t (metros, t em segundos). Qual a altura máxima?</p><div class='sol'><b>Resolução.</b> tᵥ = −40/(2·(−5)) = 4 s. h(4) = −5·16 + 160 = <b>80 m</b>. (Ou direto: yᵥ = −Δ/4a = −1600/(−20) = 80.) O tempo de subida (4 s) é distrator clássico.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>“Altura máxima”, “lucro máximo”, “área máxima”? Vértice na veia:</p><ol class='passos'><li>Escreva a função no formato ax² + bx + c e identifique a, b, c (com sinais!).</li><li>O x do máximo/mínimo: xᵥ = −b/(2a).</li><li>O VALOR máximo/mínimo: substitua xᵥ na função (ou yᵥ = −Δ/4a).</li><li>Confira o que a questão pede: o instante (xᵥ) ou o valor (yᵥ)?</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>O lucro de uma lanchonete é L(x) = −x² + 40x − 300 (x = lanches vendidos). Qual o lucro máximo?</p><div class='sol'><b>Passo 1:</b> a = −1 (boca para baixo → tem máximo), b = 40.<br><b>Passo 2:</b> xᵥ = −40/(2·(−1)) = 20 lanches.<br><b>Passo 3:</b> L(20) = −400 + 800 − 300 = <b>R$ 100</b> de lucro máximo. (Responder “20” seria responder a pergunta errada!)</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>A pergunta é a altura máxima (yᵥ) ou o instante do máximo (xᵥ)? São respostas diferentes!</li><li>f(3) = 3² − 4·3 + 3 = 0 — não estranhe resultado zero, é só uma raiz.</li><li>Raízes da função = pontos onde o gráfico corta o eixo x.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='30' y1='150' x2='490' y2='150' stroke='#52608f' stroke-width='1.5'/>\n<path d='M80 40 Q 260 320 440 40' fill='none' stroke='#6B89FF' stroke-width='2.5'/>\n<circle cx='128' cy='150' r='5' fill='#34d399'/><circle cx='392' cy='150' r='5' fill='#34d399'/>\n<text x='118' y='138' fill='#34d399' font-size='12'>x₁</text><text x='396' y='138' fill='#34d399' font-size='12'>x₂</text>\n<circle cx='260' cy='178' r='6' fill='#fbbf24'/>\n<text x='260' y='205' fill='#fbbf24' font-size='12.5' text-anchor='middle' font-weight='bold'>vértice: xᵥ = −b/2a (mín ou máx)</text>\n<text x='260' y='28' fill='#8fa3d8' font-size='12' text-anchor='middle'>a &gt; 0: boca pra CIMA (sorriso = tem mínimo) · a &lt; 0: boca pra BAIXO (tem máximo)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Para y = x² − 6x + 5, qual o x do vértice e ele é mínimo ou máximo?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>xᵥ = −b/2a = 6/2 = <b>3</b>. Como a = 1 &gt; 0 (boca pra cima), é ponto de <b>mínimo</b> (yᵥ = 9 − 18 + 5 = −4).</div></details>" }
    ]
  },

  {
    id: 'm-exp-log',
    titulo: 'Funções Exponencial e Logarítmica',
    aulaIds: ['mat-13'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Exponencial: a incógnita está no <b>expoente</b> (crescimento/decaimento). Logaritmo é a operação inversa: <b>log_b(a) = x ⇔ bˣ = a</b>. “Quanto tempo até dobrar/passar de X?” é quase sempre log.</p>" },
      { ic: '🧮', t: 'Propriedades (decore!)', h: "<ul><li>log(a·b) = log a + log b &nbsp;|&nbsp; log(a/b) = log a − log b</li><li>log(aⁿ) = n·log a — a propriedade que “desce o expoente”.</li><li>Mudança de base: log_b(a) = log a / log b.</li><li>log_b(1) = 0; log_b(b) = 1. Condições: base &gt; 0, base ≠ 1, logaritmando &gt; 0.</li><li>Equação exponencial: iguale as bases. 3ˣ = 243 → 3ˣ = 3⁵ → x = 5.</li><li>Valores usuais dados na prova: log 2 ≈ 0,30 e log 3 ≈ 0,48 → log 5 = 1 − log 2 = 0,70.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) T(x) = log₈(x) é o tempo (ms) para processar x bits. Com log 2 = 0,30, quanto tempo para 250 bits?</p><div class='sol'><b>Resolução.</b> T = log 250 / log 8. log 250 = log(1000/4) = 3 − 2·0,30 = 2,40. log 8 = 3·0,30 = 0,90. T = 2,40/0,90 ≈ <b>2,66 ms</b>. Reescrever 250 como 1000/4 evita conta suja — truque típico da banca.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Equação exponencial ou logarítmica? Receita:</p><ol class='passos'><li>Exponencial: escreva os DOIS lados na mesma base e iguale os expoentes (243 = 3⁵, 32 = 2⁵, 125 = 5³…).</li><li>“Quanto tempo até passar de X?” → aplique log dos dois lados e use log(aⁿ) = n·log a.</li><li>Use os valores dados na prova (log 2 ≈ 0,30; log 3 ≈ 0,48) e derive: log 5 = 1 − log 2.</li><li>Reescreva números feios: 250 = 1000/4 facilita demais o log.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Resolva 2^(x+1) = 32.</p><div class='sol'><b>Passo 1:</b> mesma base: 32 = 2⁵.<br><b>Passo 2:</b> bases iguais → expoentes iguais: x + 1 = 5.<br><b>Resposta:</b> x = <b>4</b>. Confira: 2⁵ = 32 ✓</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>log(a + b) ≠ log a + log b — propriedade vale para PRODUTO.</li><li>3^(2x−5) &gt; 243: iguale bases (243 = 3⁵) → 2x − 5 &gt; 5 → x &gt; 5.</li><li>Em decaimento R(t) = k·(0,5)^(t/2), o k é o valor INICIAL (ex.: 5 latas × 0,6 = 3 g/L).</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='40' y1='180' x2='480' y2='180' stroke='#52608f' stroke-width='1.5'/>\n<line x1='70' y1='210' x2='70' y2='20' stroke='#52608f' stroke-width='1.5'/>\n<path d='M50 172 C 200 168 300 140 430 34' fill='none' stroke='#34d399' stroke-width='2.5'/>\n<circle cx='70' cy='164' r='5' fill='#fbbf24'/>\n<text x='92' y='158' fill='#fbbf24' font-size='12'>(0, 1): a⁰ = 1</text>\n<text x='330' y='52' fill='#34d399' font-size='13' font-weight='bold'>y = aˣ (a &gt; 1)</text>\n<text x='330' y='72' fill='#8fa3d8' font-size='11.5'>cresce cada vez mais rápido</text>\n<text x='260' y='208' fill='#8fa3d8' font-size='12' text-anchor='middle'>log é a pergunta inversa: log₂(8) = “2 elevado a QUANTO dá 8?” → 3</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Calcule log₂(64).</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>“2 elevado a quanto dá 64?” → 2⁶ = 64 → log₂(64) = <b>6</b>.</div></details>" }
    ]
  },

  {
    id: 'm-razao-proporcao',
    titulo: 'Razão, Proporção e Regra de Três',
    aulaIds: ['mat-14', 'mb-05'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Razão compara grandezas por divisão; proporção é a igualdade de duas razões (a/b = c/d ⇔ <b>a·d = b·c</b>). Antes de qualquer regra de três, pergunte: as grandezas são <b>diretas</b> (aumenta→aumenta) ou <b>inversas</b> (aumenta→diminui)?</p>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li><b>Regra de três simples direta</b>: multiplica em cruz.</li><li><b>Inversa</b> (velocidade×tempo, operários×dias): multiplica em LINHA — 3 operários/12 dias → 6 operários: 3·12 = 6·x → x = 6 dias.</li><li><b>Composta</b>: monte colunas, classifique cada grandeza em relação à incógnita e inverta as inversas.</li><li><b>Divisão proporcional</b>: divida pelo total das partes. R$ 2.750 proporcional a 10, 15 e 30 → 55 partes → R$ 50 cada → o maior leva 30·50 = R$ 1.500.</li><li><b>Escala</b>: 1:50.000 → 8 cm no mapa = 8 × 50.000 cm = 4 km reais.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) Um elevador transporta 9 mulheres ou 6 homens. Com 6 mulheres já dentro, quantos homens ainda cabem, no máximo?</p><div class='sol'><b>Resolução.</b> 9 mulheres ⇔ 6 homens → 3 mulheres ⇔ 2 homens. Restam 3 “vagas de mulher” = <b>2 homens</b>. Proporção entre capacidades, sem fórmula decorada.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Regra de três COMPOSTA sem medo — receita infalível:</p><ol class='passos'><li>Monte uma coluna por grandeza e marque a linha da pergunta (x).</li><li>Compare CADA coluna com a coluna do x: se andam juntas (↑↑) mantém; se opostas (↑↓) INVERTA a coluna.</li><li>Multiplique as frações e resolva.</li><li>Teste de sanidade no final: “a resposta faz sentido?” (mais máquinas ⇒ menos dias?).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>6 máquinas produzem 1.200 peças em 5 dias. Em quantos dias 4 máquinas produzem 1.600 peças?</p><div class='sol'><b>Passo 1:</b> menos máquinas → MAIS dias (inversa: inverte 6/4 → fica ×6/4). Mais peças → MAIS dias (direta: ×1600/1200).<br><b>Passo 2:</b> dias = 5 × (6/4) × (1600/1200) = 5 × 1,5 × 4/3.<br><b>Resposta:</b> <b>10 dias</b>. Sanidade: metade a menos de máquinas e mais peças… demorar o dobro faz sentido ✓</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Mais operários, MENOS dias: inversa — quem multiplica em cruz aqui erra a questão inteira.</li><li>Na composta, cada coluna é classificada SEPARADAMENTE em relação à incógnita.</li><li>Divisão INVERSAMENTE proporcional a a, b, c = diretamente proporcional a 1/a, 1/b, 1/c.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 190' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='30' y='30' width='210' height='120' rx='12' fill='rgba(52,211,153,.07)' stroke='#34d399' stroke-width='1.5'/>\n<text x='135' y='56' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>DIRETA: ↑ ↑</text>\n<text x='135' y='84' fill='#8fa3d8' font-size='12' text-anchor='middle'>mais operários → mais muro</text>\n<text x='135' y='106' fill='#dbe3f8' font-size='12.5' text-anchor='middle' font-weight='bold'>multiplica em CRUZ ✗</text>\n<rect x='280' y='30' width='210' height='120' rx='12' fill='rgba(251,146,60,.07)' stroke='#fb923c' stroke-width='1.5'/>\n<text x='385' y='56' fill='#fb923c' font-size='13' text-anchor='middle' font-weight='bold'>INVERSA: ↑ ↓</text>\n<text x='385' y='84' fill='#8fa3d8' font-size='12' text-anchor='middle'>mais operários → menos dias</text>\n<text x='385' y='106' fill='#dbe3f8' font-size='12.5' text-anchor='middle' font-weight='bold'>multiplica em LINHA =</text>\n<text x='260' y='178' fill='#8fa3d8' font-size='12' text-anchor='middle'>Antes de armar a regra de três, pergunte: “se uma sobe, a outra sobe ou desce?”</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>4 torneiras enchem um tanque em 6 horas. Em quanto tempo 8 torneiras enchem o mesmo tanque?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Mais torneiras → MENOS tempo (inversa): multiplica em linha: 4 · 6 = 8 · x → x = <b>3 horas</b>.</div></details>" }
    ]
  },

  {
    id: 'm-porcentagem',
    titulo: 'Porcentagem',
    aulaIds: ['mat-15', 'cr-03'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Porcentagem é fração de denominador 100. A ferramenta profissional é o <b>fator multiplicativo</b>: aumentar 25% = ×1,25; descontar 20% = ×0,80. Variações sucessivas? <b>Multiplique os fatores</b> — nunca some os percentuais.</p>" },
      { ic: '🧮', t: 'Ferramentas que caem em prova', h: "<ul><li>x% de V = (x/100)·V. 20% de 350 = 70.</li><li><b>Aumentos/descontos sucessivos</b>: +20% e depois −20% → 1,2 × 0,8 = 0,96 → caiu 4% (não volta ao original!).</li><li><b>Variação acumulada</b>: −20% e −10% → 0,8 × 0,9 = 0,72 → queda de 28%.</li><li><b>Voltar no tempo</b>: cresceu 25% ao ano por 3 anos até 1000 → início = 1000/1,25³ = 512.</li><li>“A passou a ganhar 25% a mais que B” ≠ “B ganha 25% a menos que A” (bases diferentes!).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(UNEB · CFO PM BA/2023) Um atleta acertou 70% de 90 arremessos. Após mais 30, foi para 75% do total; após outros 30, para 80% do total. Quantos acertos ao final?</p><div class='sol'><b>Resolução.</b> Total final: 90 + 30 + 30 = 150 arremessos. 80% de 150 = <b>120 acertos</b>. A banca dá etapas intermediárias para te perder — a pergunta usa só o total final.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Porcentagem sem armadilha — pense sempre em FATOR:</p><ol class='passos'><li>Aumento de x% → multiplique por (1 + x/100); desconto → (1 − x/100).</li><li>Variações em sequência? Multiplique os fatores, NUNCA some os percentuais.</li><li>“Voltar no tempo” (valor antes do aumento)? DIVIDA pelo fator.</li><li>Variação total: compare o produto dos fatores com 1 (0,96 → caiu 4%).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Um produto perdeu 20% do preço. Quantos % precisa SUBIR para voltar ao valor original?</p><div class='sol'><b>Passo 1:</b> preço virou 0,80 do original (digamos R$ 100 → R$ 80).<br><b>Passo 2:</b> para voltar de 80 a 100, o aumento é sobre 80: 20/80 = 0,25.<br><b>Resposta:</b> <b>25%</b> (e não 20%!). A base mudou — essa questão derruba multidões.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>+20% seguido de −20% = −4% (e não zero).</li><li>Queda de 20% e depois 10%: acumulado 28% (e não 30%).</li><li>Sobre qual base é o percentual? “25% a mais que B” tem base B.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 150' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<text x='60' y='80' fill='#dbe3f8' font-size='19' font-weight='bold' text-anchor='middle'>200</text>\n<path d='M95 72 L185 72' stroke='#34d399' stroke-width='2' marker-end='url(#p1)'/>\n<text x='140' y='58' fill='#34d399' font-size='13' text-anchor='middle' font-weight='bold'>+20% → ×1,20</text>\n<text x='225' y='80' fill='#dbe3f8' font-size='19' font-weight='bold' text-anchor='middle'>240</text>\n<path d='M262 72 L352 72' stroke='#fb923c' stroke-width='2' marker-end='url(#p2)'/>\n<text x='307' y='58' fill='#fb923c' font-size='13' text-anchor='middle' font-weight='bold'>−20% → ×0,80</text>\n<text x='395' y='80' fill='#dbe3f8' font-size='19' font-weight='bold' text-anchor='middle'>192</text>\n<text x='260' y='128' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>NÃO voltou para 200! Sucessivos = multiplicar fatores (1,2 × 0,8 = 0,96 → −4%)</text>\n<defs><marker id='p1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><path d='M0,0 L6,3 L0,6 Z' fill='#34d399'/></marker>\n<marker id='p2' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><path d='M0,0 L6,3 L0,6 Z' fill='#fb923c'/></marker></defs>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Um produto de R$ 150 aumentou 20%. Qual o novo preço?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Fator: ×1,20 → 150 · 1,2 = <b>R$ 180</b>.</div></details>" }
    ]
  },

  {
    id: 'm-sistemas-matrizes',
    titulo: 'Sistemas Lineares, Matrizes e Determinantes',
    aulaIds: ['mat-16'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Sistema linear: traduza o problema em equações e resolva por <b>substituição</b> ou <b>adição</b>. Classificação: <b>SPD</b> (solução única), <b>SPI</b> (infinitas — uma equação é múltipla da outra), <b>SI</b> (impossível — retas paralelas).</p>" },
      { ic: '🧮', t: 'Matrizes e determinantes', h: "<ul><li>Matriz m×n: m linhas, n colunas. Elemento a₍ᵢⱼ₎: i = linha, j = coluna.</li><li>Construção por lei: aᵢⱼ = |i − 3j| numa 3×3 → linhas (2,5,8), (1,4,7), (0,3,6).</li><li><b>Determinante 2×2</b>: ad − bc.</li><li><b>3×3 (Sarrus)</b>: repita as duas primeiras colunas; some os produtos das diagonais principais e subtraia os das secundárias.</li><li>Linha/coluna de zeros → det = 0. Duas linhas proporcionais (ou em PA encadeada) → det = 0.</li><li>det(A·B) = det(A)·det(B); trocar duas linhas inverte o sinal do det.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(FCC · Soldado PM BA/2023) Três camisas e duas calças custam R$ 455; um conjunto de calça e camisa custa R$ 190. Quanto custam duas camisas e uma calça?</p><div class='sol'><b>Resolução.</b> 3c + 2p = 455 e c + p = 190. Da segunda: p = 190 − c → 3c + 380 − 2c = 455 → c = 75, p = 115. Resposta: 2·75 + 115 = <b>R$ 265</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Montando sistema a partir do problema — receita:</p><ol class='passos'><li>Dê nome às incógnitas (c = camisa, p = calça) e escreva UMA equação por frase do enunciado.</li><li>Some ou subtraia as equações para eliminar uma letra (método da adição).</li><li>Ache a primeira incógnita, substitua e ache a outra.</li><li>Responda À PERGUNTA (às vezes pedem 2c + p, não c e p separados).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Resolva por adição: x + y = 10 e x − y = 4.</p><div class='sol'><b>Passo 1:</b> some as duas equações: (x+y) + (x−y) = 10 + 4 → 2x = 14 → x = 7.<br><b>Passo 2:</b> substitua: 7 + y = 10 → y = 3.<br><b>Resposta:</b> x = <b>7</b> e y = <b>3</b>. O “y” somado com “−y” se cancela — por isso “método da adição”.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>x + y = 6 e 2x + 2y = 12: a 2ª é o dobro da 1ª → <b>infinitas soluções</b> (SPI), não “duas”.</li><li>Em aᵢⱼ, i é LINHA e j é COLUNA — inverter detona a matriz inteira.</li><li>det = 0 não significa matriz nula — significa linhas/colunas dependentes.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<text x='120' y='30' fill='#8fa3d8' font-size='12' text-anchor='middle'>aᵢⱼ → i = LINHA, j = COLUNA</text>\n<rect x='60' y='50' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='120' y='50' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='180' y='50' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='60' y='94' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='120' y='94' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='180' y='94' width='52' height='36' rx='6' fill='rgba(251,191,36,.25)' stroke='#6B89FF'/><rect x='60' y='138' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='120' y='138' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/><rect x='180' y='138' width='52' height='36' rx='6' fill='rgba(107,137,255,.08)' stroke='#6B89FF'/>\n<text x='146' y='119' fill='#fbbf24' font-size='14' text-anchor='middle' font-weight='bold'>a₂₃</text>\n<path d='M30 112 L52 112' stroke='#fbbf24' stroke-width='2'/><text x='22' y='116' fill='#fbbf24' font-size='11' text-anchor='end'>linha 2</text>\n<path d='M206 36 L206 46' stroke='#fbbf24' stroke-width='2'/><text x='206' y='208' fill='#fbbf24' font-size='11' text-anchor='middle'>coluna 3</text>\n<text x='390' y='70' fill='#dbe3f8' font-size='13' font-weight='bold'>det 2×2 = ad − bc</text>\n<text x='390' y='95' fill='#8fa3d8' font-size='11.5'>3×3 → Sarrus (repete</text>\n<text x='390' y='112' fill='#8fa3d8' font-size='11.5'>as 2 primeiras colunas)</text>\n<text x='390' y='140' fill='#8fa3d8' font-size='11.5'>linhas proporcionais</text>\n<text x='390' y='157' fill='#8fa3d8' font-size='11.5'>→ det = 0</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Resolva: x + y = 10 e x − y = 4.</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Somando as equações: 2x = 14 → x = <b>7</b> → y = <b>3</b>. (Método da adição.)</div></details>" }
    ]
  },

  {
    id: 'm-combinatoria',
    titulo: 'Análise Combinatória',
    aulaIds: ['mat-17'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Tudo nasce do <b>Princípio Fundamental da Contagem</b>: etapas independentes se MULTIPLICAM. A pergunta de ouro para escolher a fórmula: <b>a ordem importa?</b> Sim → arranjo/permutação. Não → combinação.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Fatorial</b>: 5! = 120; 0! = 1.</li><li><b>Permutação</b>: Pₙ = n! — todos em fila.</li><li><b>Permutação com repetição</b>: anagramas de CASA = 4!/2! = 12 (o A repete).</li><li><b>Arranjo</b> (ordem importa): A(n,p) = n!/(n−p)! — pódio, senha, cargos diferentes.</li><li><b>Combinação</b> (ordem NÃO importa): C(n,p) = n!/[p!(n−p)!] — duplas, comissões. C(5,2) = 10.</li><li>Posições com restrição: trave primeiro as posições restritas, multiplique o resto.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) A placa de um veículo tinha 3 vogais distintas e 4 algarismos distintos, sendo os dois últimos os dígitos 0 e 1. Quantos veículos devem ser investigados?</p><div class='sol'><b>Resolução.</b> Vogais distintas: 5·4·3 = 60. Dois últimos dígitos: 0 e 1 em alguma ordem = 2. Dois primeiros dígitos: restam 8 algarismos → 8·7 = 56. Total: 60 · 56 · 2 = <b>6.720</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Antes de qualquer fórmula, faça as 2 perguntas de ouro:</p><ol class='passos'><li>“A ordem importa?” Pódio/senha/cargos diferentes → SIM (arranjo). Comissão/dupla → NÃO (combinação).</li><li>“Pode repetir?” Senha com dígitos repetidos → multiplica direto (PFC).</li><li>Tem restrição (“começa com vogal”)? Trave a posição restrita PRIMEIRO.</li><li>Letras repetidas em anagrama? Divida pelo fatorial das repetições.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>De uma equipe de 6 policiais: (a) quantas DUPLAS de patrulha? (b) quantas escolhas de comandante e motorista?</p><div class='sol'><b>(a)</b> dupla não tem ordem → combinação: C(6,2) = 6·5/2 = <b>15</b>.<br><b>(b)</b> cargos diferentes → ordem importa → arranjo: 6·5 = <b>30</b>.<br>Mesmos 6 policiais, respostas diferentes — tudo está na pergunta “a ordem importa?”.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Comandante e motorista (funções DIFERENTES) → arranjo. Dupla de patrulha (iguais) → combinação.</li><li>Anagramas com letra repetida: divida pelo fatorial das repetições.</li><li>“Pelo menos um” em contagem: às vezes é mais rápido contar o TOTAL menos os casos sem nenhum.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<circle cx='60' cy='115' r='16' fill='rgba(107,137,255,.2)' stroke='#6B89FF' stroke-width='2'/>\n<text x='60' y='120' fill='#dbe3f8' font-size='12' text-anchor='middle'>👕</text>\n<line x1='76' y1='115' x2='170' y2='55' stroke='#52608f' stroke-width='1.4'/><line x1='76' y1='115' x2='170' y2='115' stroke='#52608f' stroke-width='1.4'/><line x1='76' y1='115' x2='170' y2='175' stroke='#52608f' stroke-width='1.4'/>\n<circle cx='186' cy='55' r='15' fill='rgba(251,191,36,.15)' stroke='#fbbf24' stroke-width='1.6'/><text x='186' y='60' fill='#fbbf24' font-size='11' text-anchor='middle'>C1</text><circle cx='186' cy='115' r='15' fill='rgba(251,191,36,.15)' stroke='#fbbf24' stroke-width='1.6'/><text x='186' y='120' fill='#fbbf24' font-size='11' text-anchor='middle'>C2</text><circle cx='186' cy='175' r='15' fill='rgba(251,191,36,.15)' stroke='#fbbf24' stroke-width='1.6'/><text x='186' y='180' fill='#fbbf24' font-size='11' text-anchor='middle'>C3</text>\n<line x1='201' y1='55' x2='290' y2='35' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='35' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='39' fill='#34d399' font-size='9' text-anchor='middle'>B1</text><line x1='201' y1='55' x2='290' y2='57' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='57' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='61' fill='#34d399' font-size='9' text-anchor='middle'>B2</text><line x1='201' y1='115' x2='290' y2='95' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='95' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='99' fill='#34d399' font-size='9' text-anchor='middle'>B1</text><line x1='201' y1='115' x2='290' y2='117' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='117' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='121' fill='#34d399' font-size='9' text-anchor='middle'>B2</text><line x1='201' y1='175' x2='290' y2='155' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='155' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='159' fill='#34d399' font-size='9' text-anchor='middle'>B1</text><line x1='201' y1='175' x2='290' y2='177' stroke='#3c4a78' stroke-width='1.2'/><circle cx='302' cy='177' r='10' fill='rgba(52,211,153,.16)' stroke='#34d399' stroke-width='1.4'/><text x='302' y='181' fill='#34d399' font-size='9' text-anchor='middle'>B2</text>\n<text x='400' y='90' fill='#dbe3f8' font-size='14' font-weight='bold'>3 calças × 2 botas</text>\n<text x='400' y='112' fill='#dbe3f8' font-size='14' font-weight='bold'>= 6 caminhos</text>\n<text x='400' y='140' fill='#8fa3d8' font-size='11.5'>etapas independentes</text>\n<text x='400' y='156' fill='#8fa3d8' font-size='11.5'>MULTIPLICAM (PFC)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Quantos anagramas tem a palavra PROVA?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>5 letras, todas diferentes → 5! = <b>120 anagramas</b>.</div></details>" }
    ]
  },

  {
    id: 'm-probabilidade',
    titulo: 'Probabilidade e Binômio de Newton',
    aulaIds: ['mat-18'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>P(evento) = casos favoráveis / casos possíveis — sempre entre 0 e 1. Em eventos em sequência, multiplique as probabilidades de cada etapa, <b>atualizando o total quando não há reposição</b>.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>União</b>: P(A ∪ B) = P(A) + P(B) − P(A ∩ B).</li><li><b>Complementar</b>: P(não A) = 1 − P(A). “Pelo menos um” = 1 − P(nenhum).</li><li><b>Sem reposição</b>: 2 soldados entre 5 soldados e 3 oficiais → 5/8 · 4/7 = 5/14.</li><li><b>Independentes</b>: P(A ∩ B) = P(A)·P(B) (com reposição, lançamentos de moeda).</li><li><b>Binômio de Newton</b>: (a+b)ⁿ tem termo geral C(n,p)·aⁿ⁻ᵖ·bᵖ; a soma dos coeficientes de (a+b)ⁿ é 2ⁿ (faça a = b = 1).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) Cada um dos 120 candidatos recebe um anagrama distinto de CFOPM. Qual a probabilidade de o anagrama sorteado começar e terminar por consoante?</p><div class='sol'><b>Resolução.</b> CFOPM: 4 consoantes e 1 vogal. Primeira posição: 4 opções de consoante; última: 3; o miolo permuta livre: 3! = 6. Favoráveis: 4·3·6 = 72 → P = 72/120 = <b>60%</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Probabilidade na prova — caminho seguro:</p><ol class='passos'><li>Conte os casos possíveis (o total do sorteio).</li><li>Conte os favoráveis (o que a questão quer).</li><li>Eventos em sequência SEM reposição? Multiplique atualizando o total a cada retirada.</li><li>“PELO MENOS um”? Vá pelo complementar: 1 − P(nenhum).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Jogando 3 moedas, qual a probabilidade de sair PELO MENOS uma cara?</p><div class='sol'><b>Passo 1:</b> o contrário de “pelo menos uma cara” é “NENHUMA cara” (3 coroas).<br><b>Passo 2:</b> P(3 coroas) = 1/2 · 1/2 · 1/2 = 1/8.<br><b>Resposta:</b> 1 − 1/8 = <b>7/8</b>. Contar os casos favoráveis um a um daria 7 contagens; pelo complementar, uma só.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Moedas: “pelo menos uma cara” em 2 lançamentos = 1 − 1/4 = 3/4 (não 1/2).</li><li>Com ou sem reposição? A frase “uma após a outra, sem repor” muda o denominador.</li><li>Dado: “número par” são 3 casos em 6 = 1/2 — confira o espaço amostral antes.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 140' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='40' y1='70' x2='480' y2='70' stroke='#6B89FF' stroke-width='3'/>\n<circle cx='40' cy='70' r='6' fill='#fb923c'/><circle cx='260' cy='70' r='6' fill='#fbbf24'/><circle cx='480' cy='70' r='6' fill='#34d399'/>\n<text x='40' y='45' fill='#fb923c' font-size='12.5' text-anchor='middle' font-weight='bold'>0 = impossível</text>\n<text x='260' y='45' fill='#fbbf24' font-size='12.5' text-anchor='middle' font-weight='bold'>1/2 = cara ou coroa</text>\n<text x='480' y='45' fill='#34d399' font-size='12.5' text-anchor='middle' font-weight='bold'>1 = certeza</text>\n<text x='260' y='112' fill='#8fa3d8' font-size='12.5' text-anchor='middle'>P = favoráveis ÷ possíveis — nunca dá negativo, nunca passa de 1 (100%)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Lançando dois dados, qual a probabilidade de a soma ser 12?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Só o par (6,6) entre 36 combinações → <b>1/36</b>.</div></details>" }
    ]
  },

  {
    id: 'm-geo-plana-triangulos',
    titulo: 'Geometria Plana: Triângulos e Conceitos',
    aulaIds: ['mat-19'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>A soma dos ângulos internos de QUALQUER triângulo é <b>180°</b>. O triângulo retângulo é o rei das provas: <b>Pitágoras</b> (a² = b² + c²) resolve distância, rampa, escada, sombra e mangueira esticada.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Área</b>: A = (base × altura)/2.</li><li><b>Pitágoras</b>: hipotenusa² = soma dos quadrados dos catetos. Ternos clássicos: 3-4-5, 5-12-13, 6-8-10 (reconhecê-los economiza minutos).</li><li><b>Semelhança</b>: lados proporcionais — sombra do poste/sombra do prédio: 6/4 = h/10 → h = 15.</li><li>Ângulos x, 2x, 3x → 6x = 180° → x = 30° (o maior = 90°).</li><li>Condição de existência: cada lado &lt; soma dos outros dois.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) De um ponto P num poste central, 20 mangueiras de luz iguais (total 260 m) vão até uma circunferência de raio 5 m no chão. Qual a altura de P?</p><div class='sol'><b>Resolução.</b> Cada mangueira: 260 ÷ 20 = 13 m. Mangueira = hipotenusa; raio = cateto: h = √(13² − 5²) = √144 = <b>12 m</b>. Terno 5-12-13 puro.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Viu escada, rampa, sombra ou poste? Triângulo retângulo na certa:</p><ol class='passos'><li>Desenhe! Chão = um cateto, altura = outro cateto, escada/rampa = hipotenusa.</li><li>Dois lados conhecidos? Pitágoras: hip² = cat² + cat².</li><li>Antes de elevar ao quadrado, confira se não é um terno clássico (3-4-5, 5-12-13) multiplicado.</li><li>Duas figuras com mesmo ângulo (poste e prédio sob o mesmo sol)? Semelhança: monte a proporção.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Uma escada de 13 m está apoiada com a base a 5 m da parede. A que altura ela toca a parede?</p><div class='sol'><b>Passo 1:</b> desenhe: escada = hipotenusa (13), base = cateto (5), altura = cateto (h).<br><b>Passo 2:</b> reconheça o terno 5-12-13 — sem conta!<br><b>Resposta:</b> <b>12 m</b>. (Pela fórmula: h = √(169 − 25) = √144 = 12 ✓)</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>A altura relativa à hipotenusa NÃO é um cateto — cuidado com a figura mental.</li><li>Na semelhança, mantenha a correspondência (sombra com sombra, altura com altura).</li><li>Triângulo 3-4-6 existe? 3 + 4 &gt; 6 ✓ existe. 3-4-8? 3 + 4 &lt; 8 ✗ não existe.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 240' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<polygon points='150,190 330,190 150,70' fill='rgba(107,137,255,.12)' stroke='#6B89FF' stroke-width='2.5'/>\n<rect x='150' y='172' width='18' height='18' fill='none' stroke='#6B89FF' stroke-width='1.6'/>\n<text x='240' y='212' fill='#dbe3f8' font-size='14' text-anchor='middle' font-weight='bold'>cateto 4</text>\n<text x='118' y='135' fill='#dbe3f8' font-size='14' text-anchor='middle' font-weight='bold'>cateto 3</text>\n<text x='262' y='118' fill='#fbbf24' font-size='14' text-anchor='middle' font-weight='bold' transform='rotate(-33 262 118)'>hipotenusa 5</text>\n<text x='370' y='84' fill='#dbe3f8' font-size='14' font-weight='bold'>Pitágoras:</text>\n<text x='370' y='106' fill='#dbe3f8' font-size='14'>5² = 3² + 4²</text>\n<text x='370' y='128' fill='#8fa3d8' font-size='12'>25 = 9 + 16 ✓</text>\n<text x='370' y='158' fill='#34d399' font-size='12' font-weight='bold'>Ternos mágicos:</text>\n<text x='370' y='176' fill='#8fa3d8' font-size='12'>3-4-5 · 5-12-13</text>\n<text x='370' y='192' fill='#8fa3d8' font-size='12'>6-8-10 · 9-12-15</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Um triângulo retângulo tem catetos 9 e 12. Quanto mede a hipotenusa?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>É o terno 3-4-5 multiplicado por 3 → <b>15</b>. (Confirme: 81 + 144 = 225 = 15².)</div></details>" }
    ]
  },

  {
    id: 'm-geo-plana-quadrilateros',
    titulo: 'Geometria Plana: Quadriláteros, Círculo e Thales',
    aulaIds: ['mat-20'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Cada figura tem sua fórmula de área — e a banca adora dar o <b>perímetro</b> para você descobrir o lado antes de calcular a área (duas etapas).</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li>Retângulo: A = b·h; quadrado: A = L² (perímetro 4L).</li><li>Paralelogramo: A = b·h; trapézio: A = (B + b)·h/2.</li><li><b>Losango</b>: A = (D · d)/2 — diagonais 10 e 24 → área 120.</li><li><b>Círculo</b>: C = 2πr e A = πr². Contorno 31,4 m (π = 3,14) → r = 5 → A = 78,5 m².</li><li><b>Polígono de n lados</b>: soma dos ângulos internos = (n − 2)·180°. Pentágono: 540°.</li><li><b>Thales</b>: retas paralelas cortadas por transversais geram segmentos proporcionais.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — estilo banca', h: "<p class='en'>Um terreno retangular tem perímetro 70 m e o comprimento excede a largura em 5 m. Qual a área?</p><div class='sol'><b>Resolução.</b> c + l = 35 e c = l + 5 → 2l + 5 = 35 → l = 15, c = 20. Área: 20 × 15 = <b>300 m²</b>. Perímetro vira sistema; área é a etapa final.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Questão de área — receita anti-erro:</p><ol class='passos'><li>Identifique a figura e escreva a fórmula ANTES de pôr números.</li><li>O enunciado deu o perímetro? Primeiro descubra o lado, só depois calcule a área.</li><li>Deu o contorno do círculo? Ache o raio por C = 2πr antes de A = πr².</li><li>Unidades: área sai em cm², m² — alternativa com unidade errada é distrator.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Um terreno em forma de trapézio tem bases de 10 m e 6 m e altura 4 m. Qual a área?</p><div class='sol'><b>Passo 1:</b> fórmula do trapézio: A = (B + b)·h/2.<br><b>Passo 2:</b> A = (10 + 6)·4/2 = 16·2.<br><b>Resposta:</b> <b>32 m²</b>. Pense assim: é a média das bases (8) vezes a altura (4).</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Dobrar o lado de um quadrado QUADRUPLICA a área (relação quadrática).</li><li>Diâmetro ≠ raio: contorno de 31,4 m dá raio 5 (não 10).</li><li>Muro com portão: perímetro MENOS a largura do portão.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<circle cx='130' cy='105' r='72' fill='rgba(107,137,255,.10)' stroke='#6B89FF' stroke-width='2.5'/>\n<line x1='130' y1='105' x2='202' y2='105' stroke='#fbbf24' stroke-width='2'/>\n<text x='166' y='96' fill='#fbbf24' font-size='13' text-anchor='middle' font-weight='bold'>r</text>\n<text x='130' y='200' fill='#8fa3d8' font-size='12' text-anchor='middle'>C = 2πr · A = πr²</text>\n<polygon points='390,35 450,105 390,175 330,105' fill='rgba(52,211,153,.12)' stroke='#34d399' stroke-width='2'/>\n<line x1='390' y1='35' x2='390' y2='175' stroke='#fbbf24' stroke-width='1.8' stroke-dasharray='5,4'/>\n<line x1='330' y1='105' x2='450' y2='105' stroke='#fbbf24' stroke-width='1.8' stroke-dasharray='5,4'/>\n<text x='398' y='66' fill='#fbbf24' font-size='12' font-weight='bold'>D</text>\n<text x='418' y='99' fill='#fbbf24' font-size='12' font-weight='bold'>d</text>\n<text x='390' y='200' fill='#8fa3d8' font-size='12' text-anchor='middle'>Losango: A = D·d/2</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Um losango tem diagonais 6 cm e 8 cm. Qual a área?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>A = D·d/2 = 6·8/2 = <b>24 cm²</b>.</div></details>" }
    ]
  },

  {
    id: 'm-geo-espacial-prismas',
    titulo: 'Geometria Espacial: Prismas e Pirâmides',
    aulaIds: ['mat-21'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Sólidos de “paredes retas”. A receita é sempre a mesma: <b>Volume = área da base × altura</b> (no prisma) e <b>V = (1/3)·A_base·h</b> (na pirâmide — um terço do prisma de mesma base).</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Área lateral do prisma</b> = perímetro da base × altura.</li><li><b>Área total</b> = lateral + 2 × base.</li><li>Cubo: V = a³, total = 6a², diagonal = a√3.</li><li>Paralelepípedo: V = a·b·c; diagonal = √(a² + b² + c²).</li><li>Pirâmide: relacione apótema, altura e meia-base por Pitágoras.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) Um prisma reto tem 12 cm de altura e base quadrada de área 16 cm². Qual a área lateral?</p><div class='sol'><b>Resolução.</b> Base de área 16 → lado 4 cm → perímetro 16 cm. Lateral = perímetro × altura = 16 × 12 = <b>192 cm²</b>. Não confunda área da base (16) com perímetro (também 16 aqui — coincidência armada pela banca!).</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Volume de caixa, piscina ou reservatório — receita:</p><ol class='passos'><li>Volume = área da base × altura. SEMPRE.</li><li>Identifique a base e calcule a área dela primeiro.</li><li>Pirâmide? Mesmo cálculo ÷ 3.</li><li>Conversão que despenca em prova: <b>1 m³ = 1.000 litros</b>; 1 cm³ = 1 mℓ.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Uma caixa d’água tem 2 m × 1,5 m de base e 1 m de altura. Quantos LITROS ela comporta?</p><div class='sol'><b>Passo 1:</b> área da base: 2 × 1,5 = 3 m².<br><b>Passo 2:</b> volume: 3 × 1 = 3 m³.<br><b>Passo 3:</b> converta: 1 m³ = 1.000 ℓ.<br><b>Resposta:</b> <b>3.000 litros</b>. Quem esquece a conversão erra por mil. 😉</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Lateral usa o PERÍMETRO da base; volume usa a ÁREA da base.</li><li>Pirâmide tem o fator 1/3 — esquecê-lo triplica o resultado.</li><li>Unidades: cm³ para volume, cm² para área — alternativas misturam de propósito.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<polygon points='110,80 270,80 310,50 150,50' fill='rgba(107,137,255,.10)' stroke='#6B89FF' stroke-width='1.8'/>\n<rect x='110' y='80' width='160' height='110' fill='rgba(107,137,255,.14)' stroke='#6B89FF' stroke-width='1.8'/>\n<polygon points='270,80 310,50 310,160 270,190' fill='rgba(107,137,255,.08)' stroke='#6B89FF' stroke-width='1.8'/>\n<line x1='110' y1='190' x2='150' y2='160' stroke='#6B89FF' stroke-width='1.2' stroke-dasharray='4,4'/>\n<line x1='150' y1='160' x2='310' y2='160' stroke='#6B89FF' stroke-width='1.2' stroke-dasharray='4,4'/>\n<line x1='150' y1='160' x2='150' y2='50' stroke='#6B89FF' stroke-width='1.2' stroke-dasharray='4,4'/>\n<text x='190' y='145' fill='#dbe3f8' font-size='13' text-anchor='middle' font-weight='bold'>base</text>\n<path d='M330 80 L330 190' stroke='#fbbf24' stroke-width='2'/>\n<text x='344' y='140' fill='#fbbf24' font-size='13' font-weight='bold'>h</text>\n<text x='420' y='95' fill='#dbe3f8' font-size='14' font-weight='bold'>V = A_base × h</text>\n<text x='420' y='120' fill='#8fa3d8' font-size='12'>Lateral = perímetro × h</text>\n<text x='420' y='145' fill='#8fa3d8' font-size='12'>Pirâmide: V ÷ 3</text>\n<text x='260' y='220' fill='#8fa3d8' font-size='12' text-anchor='middle'>Volume usa a ÁREA da base; área lateral usa o PERÍMETRO da base — não troque!</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Um cubo tem aresta 3 cm. Qual o volume e a área total?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>V = 3³ = <b>27 cm³</b>; área total = 6·3² = <b>54 cm²</b>.</div></details>" }
    ]
  },

  {
    id: 'm-geo-espacial-corpos',
    titulo: 'Geometria Espacial: Cilindro, Cone e Esfera',
    aulaIds: ['mat-22'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Corpos redondos. Cilindro segue a regra do prisma (base × altura); cone leva o fator 1/3; esfera tem fórmula própria. <b>Semelhança de sólidos</b>: razão k nos comprimentos → k² nas áreas → <b>k³ nos volumes</b>.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Cilindro</b>: V = πr²h; lateral = 2πrh.</li><li><b>Cone</b>: V = (1/3)πr²h; g² = h² + r² (geratriz); lateral = πrg.</li><li><b>Cone equilátero</b>: g = 2r e h = r√3.</li><li><b>Esfera</b>: V = (4/3)πr³; superfície = 4πr².</li><li>Líquido até fração da altura do cone: volume proporcional ao <b>cubo</b> da razão.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) Um protótipo cilíndrico tem 6 cm de diâmetro e 12 cm de altura. Quanto armazenam, aproximadamente, cem protótipos (em mℓ)?</p><div class='sol'><b>Resolução.</b> Raio = 3 cm. V = π·9·12 = 108π ≈ 339,12 cm³. Cem unidades: <b>33.912 mℓ</b> (1 cm³ = 1 mℓ). Metade do erro da turma é usar o DIÂMETRO no lugar do raio.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Cilindro, cone e esfera — receita:</p><ol class='passos'><li>O enunciado deu o DIÂMETRO? Divida por 2 antes de tudo (erro nº 1).</li><li>Cilindro: V = πr²h. Cone: igual, ÷ 3. Esfera: V = 4πr³/3.</li><li>Cone: falta um dado? g² = h² + r² (Pitágoras dentro do cone).</li><li>Sólidos semelhantes: dobrou a medida → volume ×8 (razão ao cubo).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Uma lata cilíndrica tem 6 cm de diâmetro e 10 cm de altura. Qual o volume (use π = 3,14)?</p><div class='sol'><b>Passo 1:</b> diâmetro 6 → raio 3.<br><b>Passo 2:</b> V = πr²h = 3,14 × 9 × 10.<br><b>Resposta:</b> <b>282,6 cm³</b> (≈ 282,6 mℓ — quase uma latinha de refrigerante de 269 mℓ, faz sentido!).</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Diâmetro 6 → raio 3. Sempre divida antes de elevar ao quadrado.</li><li>Água no cone: h=8 e g=10 → r = 6 (Pitágoras) ANTES do volume.</li><li>Dobrar o raio da esfera multiplica o volume por 8 (2³).</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<ellipse cx='130' cy='60' rx='55' ry='16' fill='rgba(107,137,255,.12)' stroke='#6B89FF' stroke-width='1.8'/>\n<line x1='75' y1='60' x2='75' y2='170' stroke='#6B89FF' stroke-width='1.8'/>\n<line x1='185' y1='60' x2='185' y2='170' stroke='#6B89FF' stroke-width='1.8'/>\n<ellipse cx='130' cy='170' rx='55' ry='16' fill='rgba(107,137,255,.16)' stroke='#6B89FF' stroke-width='1.8'/>\n<text x='130' y='210' fill='#8fa3d8' font-size='12' text-anchor='middle'>Cilindro: V = πr²h</text>\n<ellipse cx='330' cy='170' rx='52' ry='15' fill='rgba(251,191,36,.10)' stroke='#fbbf24' stroke-width='1.8'/>\n<line x1='278' y1='170' x2='330' y2='52' stroke='#fbbf24' stroke-width='1.8'/>\n<line x1='382' y1='170' x2='330' y2='52' stroke='#fbbf24' stroke-width='1.8'/>\n<line x1='330' y1='52' x2='330' y2='170' stroke='#fbbf24' stroke-width='1.2' stroke-dasharray='4,4'/>\n<text x='318' y='120' fill='#fbbf24' font-size='11.5'>h</text>\n<text x='372' y='112' fill='#fbbf24' font-size='11.5' font-weight='bold'>g</text>\n<text x='330' y='210' fill='#8fa3d8' font-size='12' text-anchor='middle'>Cone: V = πr²h ÷ 3 · g² = h² + r²</text>\n<text x='460' y='100' fill='#dbe3f8' font-size='12.5' font-weight='bold'>Esfera:</text>\n<text x='460' y='120' fill='#8fa3d8' font-size='12'>V = 4πr³/3</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Um cilindro tem raio 2 e altura 5. Qual o volume?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>V = πr²h = π·4·5 = <b>20π</b> (≈ 62,8 com π = 3,14).</div></details>" }
    ]
  },

  {
    id: 'm-geo-analitica',
    titulo: 'Geometria Analítica',
    aulaIds: ['mat-23'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Geometria com coordenadas: cada ponto é (x, y) e as figuras viram equações. As três contas básicas — distância, ponto médio e coeficiente angular — resolvem a maioria das questões.</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Distância</b>: d = √[(Δx)² + (Δy)²].</li><li><b>Ponto médio</b>: M = ((x₁+x₂)/2, (y₁+y₂)/2).</li><li><b>Coeficiente angular</b>: m = Δy/Δx; reta por um ponto: y − y₀ = m(x − x₀).</li><li>Paralelas: mesmo m; perpendiculares: m₁·m₂ = −1.</li><li><b>Circunferência</b>: (x − a)² + (y − b)² = r², centro (a, b). Da forma geral, complete quadrados: x² + y² + 16x + 63 = 0 → centro (−8, 0).</li><li>Equidistante de dois pontos = mediatriz do segmento.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) Um posto deve ser equidistante de R1(6,1) e R2(6,9) e ficar a 5 u.c. de R3(13,1). Qual a distância do posto a R2?</p><div class='sol'><b>Resolução.</b> Equidistante de R1 e R2 (mesmo x): y = 5. Distância 5 até R3: (x−13)² + (5−1)² = 25 → (x−13)² = 9 → x = 10 (o mais próximo). P(10,5) → d(P,R2) = √(4² + 4²) = √32 ≈ <b>5,6</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Geometria analítica — as 3 contas que resolvem a prova:</p><ol class='passos'><li>Distância entre pontos: d = √(Δx² + Δy²) — é Pitágoras disfarçado.</li><li>Ponto médio: média dos x e média dos y.</li><li>Inclinação da reta: m = Δy/Δx; paralelas têm o mesmo m.</li><li>Circunferência x² + y² + Dx + Ey + F = 0? Centro = (−D/2, −E/2).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Qual o ponto médio do segmento que liga A(2, 3) e B(8, 11)?</p><div class='sol'><b>Passo 1:</b> média dos x: (2 + 8)/2 = 5.<br><b>Passo 2:</b> média dos y: (3 + 11)/2 = 7.<br><b>Resposta:</b> M = <b>(5, 7)</b>. Ponto médio é literalmente “a média das coordenadas”.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Na equação geral da circunferência, o sinal inverte: +16x → centro com x = −8.</li><li>Reta pelos centros: ache os DOIS centros primeiro, depois m = Δy/Δx.</li><li>Distância nunca é negativa; (Δx)² elimina o sinal.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 230' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='40' y1='190' x2='490' y2='190' stroke='#52608f' stroke-width='1.5'/>\n<line x1='70' y1='215' x2='70' y2='20' stroke='#52608f' stroke-width='1.5'/>\n<circle cx='150' cy='150' r='6' fill='#6B89FF'/><text x='130' y='140' fill='#dbe3f8' font-size='13' font-weight='bold'>A(1,2)</text>\n<circle cx='390' cy='60' r='6' fill='#34d399'/><text x='402' y='55' fill='#34d399' font-size='13' font-weight='bold'>B(4,6)</text>\n<line x1='150' y1='150' x2='390' y2='60' stroke='#fbbf24' stroke-width='2.2'/>\n<line x1='150' y1='150' x2='390' y2='150' stroke='#52608f' stroke-width='1.4' stroke-dasharray='5,4'/>\n<line x1='390' y1='150' x2='390' y2='60' stroke='#52608f' stroke-width='1.4' stroke-dasharray='5,4'/>\n<text x='270' y='168' fill='#8fa3d8' font-size='12' text-anchor='middle'>Δx = 3</text>\n<text x='420' y='110' fill='#8fa3d8' font-size='12'>Δy = 4</text>\n<text x='245' y='86' fill='#fbbf24' font-size='13' font-weight='bold' transform='rotate(-20 245 86)'>d = √(3²+4²) = 5</text>\n<text x='260' y='222' fill='#8fa3d8' font-size='12' text-anchor='middle'>Distância entre pontos é só Pitágoras escondido no plano cartesiano</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Qual a distância entre A(1, 2) e B(4, 6)?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Δx = 3, Δy = 4 → d = √(9 + 16) = √25 = <b>5</b>. Terno 3-4-5 de novo!</div></details>" }
    ]
  },

  {
    id: 'm-trigonometria',
    titulo: 'Trigonometria',
    aulaIds: ['mat-24'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>No triângulo retângulo: <b>SOH-CAH-TOA</b> — sen = oposto/hipotenusa, cos = adjacente/hipotenusa, tg = oposto/adjacente. Rampas, escadas e inclinações são sempre “qual lado eu tenho, qual lado eu quero?”.</p>" },
      { ic: '🧮', t: 'Valores e identidades (decore!)', h: "<ul><li>sen 30° = 1/2 | sen 45° = √2/2 | sen 60° = √3/2 (cosseno é o espelho).</li><li>tg 45° = 1; tg 30° = √3/3; tg 60° = √3.</li><li><b>Identidade fundamental</b>: sen²θ + cos²θ = 1 (para QUALQUER ângulo).</li><li>tg = sen/cos; <b>sec²x − tg²x = 1</b>; 1 + cotg²x = cossec²x.</li><li>Lei dos senos: a/sen A = b/sen B; lei dos cossenos: a² = b² + c² − 2bc·cos A.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(FCC · Soldado PM BA/2023) Uma rampa de inclinação 30° deve alcançar 2,5 m de altura. Qual o comprimento da rampa?</p><div class='sol'><b>Resolução.</b> Altura é o lado OPOSTO; rampa é a HIPOTENUSA → seno: sen 30° = 2,5/rampa → 0,5 = 2,5/r → r = <b>5 m</b>. Identificar o par (lado que tenho / lado que quero) decide qual razão usar.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Trigonometria no triângulo retângulo — receita SOH-CAH-TOA:</p><ol class='passos'><li>Desenhe e marque o ângulo dado.</li><li>Classifique os lados EM RELAÇÃO AO ÂNGULO: oposto (na frente), adjacente (encostado), hipotenusa (o maior).</li><li>Escolha a razão que liga “o lado que TENHO” com “o lado que QUERO”: SOH (sen = O/H), CAH (cos = A/H), TOA (tg = O/A).</li><li>Monte a equação e resolva. Decore: sen30 = 1/2, sen45 = √2/2, sen60 = √3/2 (cos espelha).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Um prédio projeta uma sombra de 30 m quando o sol está a 45°. Qual a altura do prédio?</p><div class='sol'><b>Passo 1:</b> sombra = adjacente; altura = oposto → razão TOA (tangente).<br><b>Passo 2:</b> tg 45° = altura/30 e tg 45° = 1.<br><b>Resposta:</b> altura = <b>30 m</b>. A 45°, altura e sombra são sempre iguais.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>sen²(45°) + cos²(45°) = 1 — identidade fundamental, sem conta nenhuma.</li><li>f(x) = sec²x − tg²x − cos x = 1 − cos x → mínimo 0 (quando cos x = 1).</li><li>30° e 60°: o seno de um é o cosseno do outro — não troque os valores.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 240' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<polygon points='130,190 360,190 360,70' fill='rgba(107,137,255,.12)' stroke='#6B89FF' stroke-width='2.5'/>\n<rect x='342' y='172' width='18' height='18' fill='none' stroke='#6B89FF' stroke-width='1.6'/>\n<path d='M160 190 A 30 30 0 0 0 156 176' fill='none' stroke='#fbbf24' stroke-width='2'/>\n<text x='178' y='182' fill='#fbbf24' font-size='14' font-weight='bold'>θ</text>\n<text x='245' y='212' fill='#dbe3f8' font-size='13' text-anchor='middle' font-weight='bold'>adjacente (CAH)</text>\n<text x='406' y='135' fill='#dbe3f8' font-size='13' font-weight='bold'>oposto (SOH)</text>\n<text x='222' y='112' fill='#fbbf24' font-size='13' font-weight='bold' transform='rotate(-28 222 112)'>hipotenusa</text>\n<text x='130' y='52' fill='#dbe3f8' font-size='13' font-weight='bold'>sen θ = oposto/hip · cos θ = adj/hip · tg θ = oposto/adj</text>\n<text x='130' y='30' fill='#34d399' font-size='13' font-weight='bold'>SOH — CAH — TOA (decore cantando!)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Uma escada de 10 m faz 60° com o chão. A que altura ela toca a parede? (sen 60° = √3/2 ≈ 0,87)</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Altura = oposto; escada = hipotenusa → h = 10 · sen 60° = 10 · 0,87 ≈ <b>8,7 m</b> (= 5√3).</div></details>" }
    ]
  },

  {
    id: 'm-juros',
    titulo: 'Juros Simples e Compostos',
    aulaIds: ['mat-25'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p><b>Juros simples</b>: rendem sempre sobre o capital inicial (crescimento linear — PA). <b>Juros compostos</b>: rendem sobre o montante (“juros sobre juros”, crescimento exponencial — PG).</p>" },
      { ic: '🧮', t: 'Fórmulas-chave', h: "<ul><li><b>Simples</b>: J = C·i·t e M = C(1 + i·t).</li><li><b>Compostos</b>: M = C(1 + i)ᵗ.</li><li>Taxa e tempo na MESMA unidade (5% ao mês com t em meses).</li><li>Taxa nominal anual capitalizada mensalmente: divida por 12 (6% a.a. → 0,5% a.m.).</li><li>Para achar a taxa composta entre dois acréscimos consecutivos: razão entre eles = (1 + i).</li><li>Desconto comercial simples: valor atual = N(1 − i·t).</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(UNEB · CFO PM BA/2025) R$ 1.000 aplicados a juros simples de 5% ao mês. Qual o montante após 4 meses?</p><div class='sol'><b>Resolução.</b> M = 1000·(1 + 0,05·4) = 1000·1,20 = <b>R$ 1.200</b>. Nos compostos daria 1000·1,05⁴ ≈ R$ 1.215,51 — a banca cobra a diferença entre os regimes.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Questão de juros — receita:</p><ol class='passos'><li>Identifique o REGIME: “juros simples” → linear; “compostos / sobre o saldo / capitalizados” → exponencial.</li><li>Coloque taxa e tempo na MESMA unidade (% ao mês com meses).</li><li>Simples: M = C(1 + i·t). Compostos: M = C(1 + i)ᵗ.</li><li>“Quanto tempo para dobrar?” em compostos → vai precisar de log (valores dados na prova).</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>R$ 1.000 aplicados a juros COMPOSTOS de 10% ao ano. Qual o montante após 3 anos?</p><div class='sol'><b>Passo 1:</b> fator anual: 1,10.<br><b>Passo 2:</b> M = 1000 · 1,1³ = 1000 · 1,331.<br><b>Resposta:</b> <b>R$ 1.331</b>. Nos juros simples seriam R$ 1.300 — os R$ 31 de diferença são os “juros sobre juros”.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Dobrar capital a juros compostos: use logaritmo ou os valores de ln dados (0,015t = 0,69 → t = 46).</li><li>(M₃ − M₂)/(M₂ − M₁) = 1 + i nos compostos — atalho que resolve questão inteira.</li><li>Simples: montantes em PA; compostos: em PG. Identifique o regime ANTES da fórmula.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<line x1='50' y1='180' x2='490' y2='180' stroke='#52608f' stroke-width='1.5'/>\n<line x1='70' y1='205' x2='70' y2='25' stroke='#52608f' stroke-width='1.5'/>\n<line x1='70' y1='160' x2='450' y2='90' stroke='#6B89FF' stroke-width='2.4'/>\n<path d='M70 160 C 230 152 360 120 450 38' fill='none' stroke='#34d399' stroke-width='2.4'/>\n<text x='360' y='120' fill='#6B89FF' font-size='12.5' font-weight='bold'>SIMPLES: reta (PA)</text>\n<text x='268' y='66' fill='#34d399' font-size='12.5' font-weight='bold'>COMPOSTOS: curva (PG)</text>\n<text x='280' y='210 ' fill='#8fa3d8' font-size='12' text-anchor='middle'>No começo andam juntos — com o tempo, os compostos disparam (juros sobre juros)</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>R$ 2.000 a juros simples de 3% ao mês, por 5 meses. Qual o montante?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>J = 2000 · 0,03 · 5 = 300 → M = 2000 + 300 = <b>R$ 2.300</b>.</div></details>" }
    ]
  },

  {
    id: 'm-estatistica',
    titulo: 'Estatística Descritiva e Gráficos',
    aulaIds: ['mat-26', 'cr-05'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p>Três medidas de tendência central: <b>média</b> (soma/quantidade), <b>mediana</b> (o do meio com dados ORDENADOS) e <b>moda</b> (o que mais repete). Dispersão: variância e <b>desvio padrão</b> medem o “espalhamento”.</p>" },
      { ic: '🧮', t: 'Propriedades que caem em prova', h: "<ul><li>Mediana com n par = média dos dois centrais.</li><li><b>Somar constante k</b> a todos os dados: média soma k, <b>desvio padrão NÃO muda</b>.</li><li><b>Multiplicar por k</b>: média multiplica por k e desvio padrão por |k|.</li><li>Média ponderada: Σ(valor × peso)/Σ(pesos).</li><li>Se média = mediana, a distribuição é “equilibrada” — útil para achar incógnitas em rol ordenado.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(CONSULTEC · CFO PM BA) No rol ordenado 4, 5, 5, 9, a, 14, 16, 18, b, 21, a média e a mediana valem 12. Calcule b − a.</p><div class='sol'><b>Resolução.</b> Mediana (5º e 6º): (a + 14)/2 = 12 → a = 10. Média: soma = 120 → 4+5+5+9+10+14+16+18+21 = 102 → b = 18. b − a = <b>8</b>.</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Média, mediana e moda — receita:</p><ol class='passos'><li>MEDIANA: ordene o rol primeiro. Sempre. Quantidade par → média dos dois do meio.</li><li>Média com pesos: Σ(valor × peso) ÷ Σ(pesos).</li><li>Deram a média e pedem um valor que falta? Use a SOMA: soma = média × quantidade.</li><li>Somar uma constante: média muda, desvio NÃO. Multiplicar: os dois mudam.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>Um aluno tirou 7,0 na prova 1 (peso 2) e 9,0 na prova 2 (peso 3). Qual a média ponderada?</p><div class='sol'><b>Passo 1:</b> multiplique cada nota pelo peso: 7×2 = 14 e 9×3 = 27.<br><b>Passo 2:</b> some e divida pela soma dos pesos: (14 + 27)/(2 + 3) = 41/5.<br><b>Resposta:</b> <b>8,2</b>. A nota com mais peso “puxa” a média para perto dela.</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>+1 ponto para todos → desvio padrão IGUAL (D₂' = D₂); +20% em todos → desvio também aumenta 20%.</li><li>Mediana exige ORDENAR primeiro — rol bagunçado é armadilha.</li><li>Média 12 com 10 valores → a soma é 120 (use a soma, não tente “chutar” valores).</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<div class='figura'><svg viewBox='0 0 520 220' width='100%' style='max-width:520px;display:block;margin:0 auto' xmlns='http://www.w3.org/2000/svg' font-family='Arial,Helvetica,sans-serif'>\n<rect x='90' y='114' width='42' height='56' rx='5' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/><text x='111' y='188' fill='#8fa3d8' font-size='11' text-anchor='middle'>seg</text><text x='111' y='106' fill='#dbe3f8' font-size='12' text-anchor='middle' font-weight='bold'>4</text><rect x='160' y='72' width='42' height='98' rx='5' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/><text x='181' y='188' fill='#8fa3d8' font-size='11' text-anchor='middle'>ter</text><text x='181' y='64' fill='#dbe3f8' font-size='12' text-anchor='middle' font-weight='bold'>7</text><rect x='230' y='100' width='42' height='70' rx='5' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/><text x='251' y='188' fill='#8fa3d8' font-size='11' text-anchor='middle'>qua</text><text x='251' y='92' fill='#dbe3f8' font-size='12' text-anchor='middle' font-weight='bold'>5</text><rect x='300' y='44' width='42' height='126' rx='5' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/><text x='321' y='188' fill='#8fa3d8' font-size='11' text-anchor='middle'>qui</text><text x='321' y='36' fill='#dbe3f8' font-size='12' text-anchor='middle' font-weight='bold'>9</text><rect x='370' y='100' width='42' height='70' rx='5' fill='rgba(107,137,255,.45)' stroke='#6B89FF'/><text x='391' y='188' fill='#8fa3d8' font-size='11' text-anchor='middle'>sex</text><text x='391' y='92' fill='#dbe3f8' font-size='12' text-anchor='middle' font-weight='bold'>5</text>\n<line x1='80' y1='86' x2='460' y2='86' stroke='#fbbf24' stroke-width='2' stroke-dasharray='6,4'/>\n<text x='468' y='90' fill='#fbbf24' font-size='12' font-weight='bold'>média = 6</text>\n<text x='260' y='212' fill='#8fa3d8' font-size='12' text-anchor='middle'>Média equilibra a “gangorra” · Mediana = o do MEIO (ordenado) · Moda = o que mais repete</text>\n</svg></div>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Qual a mediana de 7, 3, 9, 5, 1?</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>ORDENE primeiro: 1, 3, 5, 7, 9 → o do meio é <b>5</b>.</div></details>" }
    ]
  },

  {
    id: 'm-logica',
    titulo: 'Lógica Matemática: Proposições e Argumentos',
    aulaIds: ['mat-lg', 'cr-04'],
    pdfOriginal: null,
    secoes: [
      { ic: '📌', t: 'A ideia central', h: "<p><b>Proposição</b> é uma frase declarativa que pode ser classificada em V ou F (perguntas, exclamações e ordens NÃO são proposições). Conectivos: ∧ (e), ∨ (ou), → (se…então), ↔ (se e somente se), ~ (não).</p>" },
      { ic: '🧮', t: 'Tabela-verdade e equivalências (decore!)', h: "<ul><li><b>∧</b> só é V quando os dois são V. <b>∨</b> só é F quando os dois são F.</li><li><b>p → q</b> só é F quando p = V e q = F (“promessa quebrada”).</li><li><b>De Morgan</b>: ~(p ∧ q) = ~p ∨ ~q | ~(p ∨ q) = ~p ∧ ~q.</li><li><b>Negação do condicional</b>: ~(p → q) = p ∧ ~q (mantém a 1ª, nega a 2ª).</li><li><b>Equivalências do condicional</b>: p → q ≡ ~q → ~p (contrapositiva) ≡ ~p ∨ q.</li><li><b>Quantificadores</b>: ~(todo A é B) = “existe A que não é B”; ~(existe) = “nenhum”.</li><li>“p somente se q” = p → q; p é condição SUFICIENTE para q.</li></ul>" },
      { ic: '✏️', t: 'Exemplo resolvido — questão real', h: "<p class='en'>(FCC · Soldado PM BA/2012) Negue: “Estou com saúde e sou feliz”.</p><div class='sol'><b>Resolução.</b> De Morgan no “e”: nega os dois e troca por “ou” → <b>“Não estou com saúde OU não sou feliz”</b>. Quem responde “não estou com saúde e não sou feliz” cai na pegadinha (essa é a negação do “ou”).</div>" },
      { ic: '🧭', t: 'Receita de bolo — como atacar na prova', h: "<p>Negar proposições — receita que resolve metade da prova de RL:</p><ol class='passos'><li>Negar “E” → vira “OU” com tudo negado (De Morgan).</li><li>Negar “OU” → vira “E” com tudo negado.</li><li>Negar “Se p, então q” → “p E não q” (mantém a primeira, nega a segunda — NÃO vira outro “se…então”).</li><li>Negar “TODO A é B” → “ALGUM A não é B”; negar “ALGUM” → “NENHUM”.</li></ol>" },
      { ic: '✏️', t: 'Mais um exemplo, passo a passo', h: "<p class='en'>“Se João estuda, então João passa.” Sabe-se que João NÃO passou. O que se conclui?</p><div class='sol'><b>Passo 1:</b> o condicional verdadeiro com consequente falso obriga o antecedente a ser falso (modus tollens — a contrapositiva em ação).<br><b>Resposta:</b> <b>João não estudou</b>. Cuidado: se soubéssemos apenas que João PASSOU, NADA se concluiria (passar não garante que estudou).</div>" },
      { ic: '⚠️', t: 'Pegadinhas da banca', h: "<ul><li>Negação de “todos têm 13 anos”: basta UM diferente (não é “nenhum tem”).</li><li>Modus ponens: “se chover, adia” + “choveu” → adiou. Não dá para concluir nada sobre cancelar.</li><li>Verdade/mentira: teste as alternativas contra TODAS as falas — só uma ordem fecha sem contradição.</li></ul>" },
      { ic: '🖼️', t: 'Esquema visual', h: "<table class='tab'>\n<tr><th>p</th><th>q</th><th>p ∧ q (E)</th><th>p ∨ q (OU)</th><th>p → q (se…então)</th></tr>\n<tr><td>V</td><td>V</td><td class='ok'>V</td><td class='ok'>V</td><td class='ok'>V</td></tr>\n<tr><td>V</td><td>F</td><td class='no'>F</td><td class='ok'>V</td><td class='no'>F ⚠️</td></tr>\n<tr><td>F</td><td>V</td><td class='no'>F</td><td class='ok'>V</td><td class='ok'>V</td></tr>\n<tr><td>F</td><td>F</td><td class='no'>F</td><td class='no'>F</td><td class='ok'>V</td></tr>\n</table>\n<p style='text-align:center'>O condicional só é FALSO na linha V → F (“prometeu e não cumpriu”). Decore essa linha!</p>" },
      { ic: '🏋️', t: 'Treine agora', h: "<p class='en'>Negue a proposição: “Todos os soldados correm”.</p><details><summary>👁 Toque para ver a resposta</summary><div class='sol'>Negação de “todo” = “pelo menos um não”: <b>“Pelo menos um soldado não corre”</b>. (Não é “nenhum soldado corre”!)</div></details>" }
    ]
  }

];

/* ════════════════════════════════════════════════════════════
   INTEGRAÇÃO COM AS AULAS
   O material teórico do assunto vira o "PDF da Aula"
   (material.html?id=...). Requer data.js carregado ANTES.
   ════════════════════════════════════════════════════════════ */
(function _integrarMateriaisNasAulas() {
  if (typeof PL_CATALOG === 'undefined' || !PL_CATALOG.cursos) return;
  const mats = window.PL_MATERIAIS || [];
  Object.values(PL_CATALOG.cursos).forEach(curso => {
    (curso.aulas || []).forEach(aula => {
      if (!aula.materiais) return;
      const m = mats.find(x => Array.isArray(x.aulaIds) &&
        x.aulaIds.some(s => aula.id === s || aula.id.endsWith('-' + s)));
      if (m) aula.materiais.pdf = 'material.html?id=' + m.id;
    });
  });
})();
